I18N.register("de", {
  q: {
    "TPR1_01": ["Was kommt als nächstes? ◇, ◇◇, ◇◇◇, ◇◇◇◇, ?", "Zählen Sie die Diamanten bei jedem Schritt.", ["◇◇◇◇◇", "◇◇◇", "◇◇◇◇", "◇◇"], "Zu jedem Schritt wird eine Raute hinzugefügt: 1, 2, 3, 4, also gibt es 5 Rauten."],
    "TPR1_02": ["Was kommt als nächstes? A, B, C, D, E, ?", "Denk an die Reihenfolge der Buchstaben im Alphabet.", ["F", "G", "D", "A"], "Es sind aufeinanderfolgende Buchstaben — nach E kommt F."],
    "TPR1_03": ["Was kommt als nächstes? 1, 2, 3, 4, 5, ?", "Jede Zahl erhöht sich um denselben Schritt.", ["6", "7", "5", "8"], "Jede Zahl erhöht sich um 1, also kommt nach 5 6."],
    "TPR1_04": ["Was kommt als nächstes? 2, 4, 6, 8, ?", "Schauen Sie sich den Unterschied zwischen aufeinanderfolgenden Zahlen an.", ["10", "12", "9", "11"], "Die Schritte sind 2 mal 2. Nach 8 ist die nächste gerade Zahl 10."],
    "TPR1_05": ["Was kommt als nächstes? A, B, A, B, A, ?", "Achte auf das abwechselnde Muster.", ["B", "A", "C", "D"], "A und B wechseln sich immer ab — nach A kommt B."],
    "TPR1_06": ["Was kommt als nächstes? □, □□, □□□, ?", "Zählen Sie die Quadrate bei jedem Schritt.", ["□□□□", "□□", "□□□□□", "□□□"], "Zu jedem Schritt wird ein Quadrat hinzugefügt: 1, 2, 3, es folgen also 4 Quadrate."],
    "TPR1_07": ["Was kommt als nächstes? Z, Y, X, W, ?", "Das Alphabet geht rückwärts.", ["V", "u", "X", "T"], "Die Buchstaben stehen im Alphabet rückwärts: Z, Y, X, W, V."],
    "TPR1_08": ["Was kommt als nächstes? 10, 20, 30, 40, ?", "Jede Zahl erhöht sich um denselben Schritt.", ["50", "45", "60", "55"], "Die Schritte reichen von 10 bis 10. Nach 40 ist der nächste Term 50."],
    "TPR1_09": ["Was kommt als nächstes? 3, 6, 9, 12, ?", "Jede Zahl erhöht sich um denselben Schritt.", ["15", "14", "18", "13"], "Die Schritte sind 3 mal 3. Nach 12 ist das nächste Vielfache von 3 15."],
    "TPR1_10": ["Vervollständigen Sie das Raster: 1, 3, 5 / 7, 9, 11 / 13, 15, ?", "Listen Sie die ungeraden Zahlen der Reihe nach Zeile für Zeile auf.", ["17", "16", "19", "18"], "Das Raster listet aufeinanderfolgende ungerade Zahlen auf: 1, 3, 5, 7, …, 15, 17."],
    "TPR1_11": ["Was kommt als nächstes? ★, ★★, ★★★, ★★★★, ?", "Zählen Sie bei jedem Schritt die Sterne.", ["★★★★★", "★★★★", "★★★", "★★★★★★"], "Zu jedem Schritt wird ein Stern hinzugefügt: 1, 2, 3, 4, also folgen 5 Sterne."],
    "TPR1_12": ["Was kommt als nächstes? 6, 12, 18, 24, ?", "Jeder Term ist ein Vielfaches derselben Zahl – welcher?", ["30", "28", "36", "32"], "Die Schritte reichen von 6 bis 6. Nach 24 ist das nächste Vielfache von 6 30."],
    "TPR1_13": ["Was kommt als nächstes? M, N, O, P, ?", "Es sind aufeinanderfolgende Buchstaben des Alphabets.", ["F", "R", "N", "S"], "Die Buchstaben werden in alphabetischer Reihenfolge fortgesetzt: M, N, O, P, Q."],
    "TPR1_14": ["Was kommt als nächstes? 1, 1, 1, 1, ?", "Ändert sich der Wert jemals?", ["1", "2", "0", "3"], "Jeder Term ist 1 – das Muster ist konstant, daher ist der nächste Wert 1."],
    "TPR1_15": ["Was kommt als nächstes? ♥, ♦, ♥, ♦, ♥, ?", "Zwei Symbole wechseln sich ab.", ["♦", "♥", "♣", "♠"], "Das Muster wechselt zwischen Herz und Raute. Nach dem Herzen kommt der Diamant."],
    "TPR1_16": ["Was kommt als nächstes? 8, 16, 24, 32, ?", "Schauen Sie sich den Unterschied zwischen aufeinanderfolgenden Zahlen an.", ["40", "36", "48", "38"], "Die Schritte gehen von 8 bis 8. Nach 32 ist das nächste Vielfache von 8 40."],
    "TPR1_17": ["Was kommt als nächstes? ♠, ♠♠, ♠♠♠, ?", "Zählen Sie bei jedem Schritt die Vereinssymbole.", ["♠♠♠♠", "♠♠", "♠♠♠", "♠♠♠♠♠"], "Zu jedem Schritt wird ein Kleeblatt hinzugefügt: 1, 2, 3, es gibt also 4 Kleeblätter."],
    "TPR1_18": ["Was kommt als nächstes? 30, 27, 24, 21, ?", "Die Zahlen verringern sich um einen festen Schritt.", ["18", "20", "15", "19"], "Jede Zahl verringert sich um 3. Nach 21 ist der nächste Wert 18."],
    "TPR1_19": ["Was kommt als nächstes? 7, 14, 21, 28, ?", "Jede Zahl ist ein Vielfaches derselben Zahl.", ["35", "36", "32", "42"], "Die Schritte gehen von 7 bis 7. Nach 28 ist das nächste Vielfache von 7 35."],
    "TPR1_20": ["Vervollständigen Sie das Raster: 2, 4, 6 / 8, 10, 12 / 14, 16, ?", "Listen Sie die geraden Zahlen Zeile für Zeile auf.", ["18", "20", "17", "19"], "Das Raster listet aufeinanderfolgende gerade Zahlen auf: 2, 4, 6, 8, …, 16, 18."],
    "TPR2_01": ["Was kommt als nächstes? X, XY, XYX, XYXY, ?", "Bei jedem Schritt wird ein weiteres Zeichen hinzugefügt, abwechselnd X und Y.", ["XYXYX", "XYXYY", "YXYXY", "XYXY"], "Das Muster wächst durch abwechselnde Addition: Der 5. Term hat 5 Zeichen: XYXYX."],
    "TPR2_02": ["Raster: 3, 6, 9 / 5, 10, 15 / 8, 16, ?", "Sehen Sie sich an, wie sich jede Zeile auf die erste Zahl in der Zeile bezieht.", ["24", "20", "18", "32"], "Jede Zeile multipliziert die erste Zahl mit 1, 2, 3. Zeile 3: 8×1=8, 8×2=16, 8×3=24."],
    "TPR2_03": ["Was kommt als nächstes? AA, BB, CC, DD, ?", "Jedes Paar verwendet den nächsten Buchstaben des Alphabets.", ["EE", "FF", "DE", "AB"], "Jeder Begriff ist ein doppelter aufeinanderfolgender Buchstabe: A, B, C, D, E → EE."],
    "TPR2_04": ["Was kommt als nächstes? 1, 3, 5, 7, 9, ?", "Es sind ungerade Zahlen.", ["11", "10", "13", "12"], "Die Zeichenfolge listet aufeinanderfolgende ungerade Zahlen auf. Nach 9 ist die nächste ungerade Zahl 11."],
    "TPR2_05": ["Was kommt als nächstes? ○●, ○●○, ○●○●, ○●○●○, ?", "Bei jedem Schritt wird eine weitere Form hinzugefügt, abwechselnd ○ und ●.", ["○●○●○●", "○●○●○○", "●○●○●○", "○●○●●○"], "Das Muster wächst bei jedem Schritt um eine Form, abwechselnd ○ und ●. Das Folgende hat 6 Formen: ○●○●○●."],
    "TPR2_06": ["Was kommt als nächstes? 2, 6, 10, 14, ?", "Finden Sie den konstanten Unterschied zwischen den Begriffen.", ["18", "16", "20", "15"], "Jede Zahl erhöht sich um 4. Nach 14 ist der nächste Wert 18."],
    "TPR2_07": ["Was kommt als nächstes? AB, CD, EF, GH, ?", "Jedes Paar verwendet die nächsten beiden aufeinanderfolgenden Buchstaben.", ["IJ", "JK", "Hallo", "KL"], "Die Paare gehen jeweils zwei Buchstaben durch das Alphabet: AB, CD, EF, GH, IJ."],
    "TPR2_08": ["Raster: 1, 3, 5 / 2, 4, 6 / 3, 5, ?", "Jede Zeile beginnt mit einer höheren Zahl und fügt den gleichen Schritt hinzu.", ["7", "8", "6", "9"], "Jede Zeile listet drei Zahlen auf, die sich um 2 erhöhen. Zeile 3 beginnt bei 3: 3, 5, 7."],
    "TPR2_09": ["Was kommt als nächstes? ○, ■, ○, ■, ○, ■, ?", "Im Zyklus wiederholen sich zwei Formen.", ["○", "■", "△", "◇"], "Das Muster wechselt ○ und ■. Nach ■ folgt ○."],
    "TPR2_10": ["Was kommt als nächstes? 20, 17, 14, 11, ?", "Die Zahlen verringern sich um einen festen Betrag.", ["8", "9", "7", "10"], "Jede Zahl verringert sich um 3. Nach 11 ist der nächste Wert 8."],
    "TPR2_11": ["Was kommt als nächstes? ABA, BCB, CDC, DED, ?", "Beobachten Sie, wie sich die drei Buchstaben in jeder Gruppe bewegen.", ["EFE", "FGF", "DEF", "EEE"], "Jede Gruppe folgt dem Muster: Buchstabe, nächster Buchstabe, gleicher Anfangsbuchstabe – bei jeder Gruppe um einen Schritt verschoben. Nach DED kommt EFE."],
    "TPR2_12": ["Raster: 5, 10, 15 / 6, 12, 18 / 7, 14, ?", "Jede Zeile multipliziert die erste Zahl mit 1, 2 und 3.", ["21", "20", "24", "28"], "Reihe 3: 7×1=7, 7×2=14, 7×3=21."],
    "TPR2_13": ["Was kommt als nächstes? 0, 2, 4, 6, 8, ?", "Es sind aufeinanderfolgende gerade Zahlen, die bei 0 beginnen.", ["10", "12", "9", "11"], "Die Zeichenfolge listet gerade Zahlen auf: 0, 2, 4, 6, 8, 10."],
    "TPR2_14": ["Was kommt als nächstes? ○○, ■■, ○○, ■■, ?", "Die Formenpaare wechseln sich ab.", ["○○", "■■", "○■", "■○"], "Das Muster wechselt Paare: ○○, ■■, ○○, ■■, ○○."],
    "TPR2_15": ["Was kommt als nächstes? 3, 7, 11, 15, 19, ?", "Finden Sie den gemeinsamen Unterschied zwischen den Begriffen.", ["23", "22", "21", "24"], "Jede Zahl erhöht sich um 4. Nach 19 ist der nächste Wert 23."],
    "TPR2_16": ["Raster: 1, 2, 3 / 2, 4, 6 / 3, 6, ?", "Vergleichen Sie jede Zeile mit der Zeile darüber.", ["9", "8", "10", "12"], "Zeile n multipliziert 1, 2, 3 mit n. Reihe 3: 3×1=3, 3×2=6, 3×3=9."],
    "TPR2_17": ["Was kommt als nächstes? XY, WX, VW, UV, ?", "Jedes Paar verschiebt einen Buchstaben im Alphabet nach hinten.", ["DU", "ST", "RS", "SU"], "Jedes Paar geht um einen Buchstaben nach unten: XY → WX → VW → UV → TU."],
    "TPR2_18": ["Was kommt als nächstes? 40, 36, 32, 28, ?", "Die Zahlen nehmen um eine Konstante ab.", ["24", "25", "22", "20"], "Jede Zahl verringert sich um 4. Nach 28 ist der nächste Wert 24."],
    "TPR2_19": ["Was kommt als nächstes? ○, ○○, ■, ■■, ○, ?", "Auf eine Einzelform folgt die Doppelform und dann die nächste Form.", ["○○", "■", "○", "■■"], "Der Zyklus ist: ○ einfach, ○○ doppelt, ■ einfach, ■■ doppelt, dann wiederholen. Nach ○ kommt ○○."],
    "TPR2_20": ["Raster: 10, 20, 30 / 11, 22, 33 / 12, 24, ?", "Jede Zeile multipliziert die erste Zahl mit 1, 2 und 3.", ["36", "34", "38", "48"], "Reihe 3: 12×1=12, 12×2=24, 12×3=36."],
    "TPR3_01": ["Was kommt als nächstes? 2, 3, 5, 8, 12, ?", "Schauen Sie sich die Unterschiede zwischen aufeinanderfolgenden Begriffen an – sie erhöhen sich um 1.", ["17", "15", "16", "18"], "Die Differenzen sind 1, 2, 3, 4, also ist die nächste Differenz 5: 12 + 5 = 17."],
    "TPR3_02": ["Raster: 3, 5, 15/4, 6, 24/7, 3, ?", "In welcher Beziehung stehen die ersten beiden Spalten zur dritten?", ["21", "10", "24", "30"], "Spalte 1 × Spalte 2 = Spalte 3. Zeile 3: 7 × 3 = 21."],
    "TPR3_03": ["Was kommt als nächstes? 49, 36, 25, 16, 9, ?", "Jeder Term ist ein perfektes Quadrat – welche Quadrate sind das?", ["4", "1", "6", "3"], "Die Zeichenfolge ist 7², 6², 5², 4², 3², also folgt 2² = 4."],
    "TPR3_04": ["Was kommt als nächstes? 20, 18, 15, 11, 6, ?", "Der niedrige Betrag erhöht sich bei jedem Schritt um 1.", ["0", "1", "2", "−1"], "Die Unterschiede sind −2, −3, −4, −5, also ist der nächste −6: 6 − 6 = 0."],
    "TPR3_05": ["Raster: 3, 9, 27 / 4, 16, 64 / 6, 36, ?", "Jede Zeile verwendet Potenzen der ersten Zahl.", ["216", "180", "108", "72"], "Das Zeilenmuster ist n¹, n², n³. Reihe 3: 6, 36, 216."],
    "TPR3_06": ["Was kommt als nächstes? 3, 5, 9, 15, 23, ?", "Berechnen Sie die Unterschiede – bilden Sie Ihr eigenes Muster.", ["33", "31", "35", "29"], "Die Unterschiede sind 2, 4, 6, 8, also ist der nächste 10: 23 + 10 = 33."],
    "TPR3_07": ["Raster: 1, 5, 6 / 2, 8, 10 / 3, 11, ?", "Fügen Sie die ersten beiden Spalten in jeder Zeile hinzu.", ["14", "13", "15", "33"], "Spalte 1 + Spalte 2 = Spalte 3. Zeile 3: 3 + 11 = 14."],
    "TPR3_08": ["Was kommt als nächstes? 1, 6, 15, 28, 45, ?", "Schauen Sie sich die Unterschiede an, dann die Unterschiede dieser Unterschiede.", ["66", "60", "56", "72"], "Die Unterschiede betragen 5, 9, 13, 17 (Erhöhung um 4). Der nächste Unterschied ist 21: 45 + 21 = 66."],
    "TPR3_09": ["Was kommt als nächstes? 100, 95, 85, 70, 50, ?", "Wie stark nimmt es bei jedem Schritt ab? Dieser Betrag steigt.", ["25", "30", "20", "35"], "Die Unterschiede betragen −5, −10, −15, −20, also folgt −25: 50 − 25 = 25."],
    "TPR3_10": ["Raster: 3, 4, 12 / 5, 6, 30 / 7, 8, ?", "In welcher Beziehung steht Spalte 3 zu den Spalten 1 und 2?", ["56", "15", "48", "60"], "Spalte 1 × Spalte 2 = Spalte 3. Zeile 3: 7 × 8 = 56."],
    "TPR3_11": ["Was kommt als nächstes? 3, 8, 15, 24, 35, ?", "Versuchen Sie, jeden Term als n² minus etwas auszudrücken.", ["48", "44", "50", "42"], "Jeder Term ist n² − 1: 2²−1=3, 3²−1=8, 4²−1=15, 5²−1=24, 6²−1=35, 7²−1=48."],
    "TPR3_12": ["Raster: 2, 10, 5 / 3, 18, 6 / 4, 28, ?", "In welcher Beziehung steht Spalte 3 zu den anderen Spalten?", ["7", "8", "12", "32"], "Spalte 2 ÷ Spalte 1 = Spalte 3. Zeile 3: 28 ÷ 4 = 7."],
    "TPR3_13": ["Was kommt als nächstes? 5, 6, 8, 11, 15, 20, ?", "Die Differenzen zwischen den Termen erhöhen sich bei jedem Schritt um 1.", ["26", "25", "27", "24"], "Die Unterschiede sind 1, 2, 3, 4, 5, also ist der nächste 6: 20 + 6 = 26."],
    "TPR3_14": ["Was kommt als nächstes? 2, 5, 10, 17, 26, ?", "Probieren Sie die Formel n² + 1 für aufeinanderfolgende Werte von n aus.", ["37", "35", "38", "36"], "Jeder Term ist n² + 1: 1²+1=2, 2²+1=5, 3²+1=10, 4²+1=17, 5²+1=26, 6²+1=37."],
    "TPR3_15": ["Raster: 2, 5, 7 / 3, 4, 7 / 8, 3, ?", "Fügen Sie die ersten beiden Spalten in jeder Zeile hinzu.", ["11", "24", "5", "10"], "Spalte 1 + Spalte 2 = Spalte 3. Zeile 3: 8 + 3 = 11."],
    "TPR3_16": ["Raster: 6, 2, 3 / 15, 3, 5 / 24, 4, ?", "Teilen Sie Spalte 1 durch Spalte 2.", ["6", "8", "7", "28"], "Spalte 1 ÷ Spalte 2 = Spalte 3. Zeile 3: 24 ÷ 4 = 6."],
    "TPR3_17": ["Was kommt als nächstes? 2, 8, 32, 128, ?", "Jeder Term wird mit derselben Zahl multipliziert.", ["512", "256", "384", "640"], "Jeder Term wird mit 4 multipliziert. Nach 128 ist der nächste Term 128 × 4 = 512."],
    "TPR3_18": ["Was kommt als nächstes? 10, 12, 16, 22, 30, ?", "Sehen Sie, wie sich das Intervall zwischen den Begriffen ändert.", ["40", "38", "42", "36"], "Die Unterschiede sind 2, 4, 6, 8, also ist der nächste 10: 30 + 10 = 40."],
    "TPR3_19": ["Was kommt als nächstes? 4, 7, 12, 19, 28, ?", "Die Differenzen zwischen den Termen erhöhen sich mit jedem Schritt um 2.", ["39", "37", "41", "35"], "Die Unterschiede sind 3, 5, 7, 9, also ist der nächste 11: 28 + 11 = 39."],
    "TPR3_20": ["Raster: 4, 2, 8 / 9, 3, 27 / 16, 4, ?", "Spalte 1 ist ein perfektes Quadrat. Welche Werte hat der Würfel?", ["64", "48", "32", "20"], "Spalte 1 = n², Spalte 2 = n, Spalte 3 = n³. Zeile 3: 4² = 16, 4, 4³ = 64."],
    "TPR4_01": ["Was kommt als nächstes? 1, 16, 81, 256, ?", "Jeder Term ist eine vierte Potenz.", ["625", "512", "500", "1024"], "Die Zeichenfolge ist 1⁴, 2⁴, 3⁴, 4⁴, also folgt 5⁴ = 625."],
    "TPR4_02": ["Raster: 5, 25, 125 / 6, 36, 216 / 7, 49, ?", "Jede Zeile zeigt n, n², n³.", ["343", "294", "350", "336"], "Zeile 3: 7¹ = 7, 7² = 49, 7³ = 343."],
    "TPR4_03": ["Was kommt als nächstes? 2, 8, 26, 80, 242, ?", "Versuchen Sie, jeden Term als Potenz von 3 minus 1 auszudrücken.", ["728", "486", "720", "500"], "Jeder Term ist 3ⁿ − 1: 3¹−1=2, 3²−1=8, 3³−1=26, 3⁴−1=80, 3⁵−1=242, 3⁶−1=728."],
    "TPR4_04": ["Was kommt als nächstes? 1, 4, 13, 40, 121, ?", "Jeder Term verdreifacht sich und erhöht sich dann um 1.", ["364", "242", "360", "400"], "Jeder Term = vorhergehend × 3 + 1: 1→4, 4→13, 13→40, 40→121, 121→364."],
    "TPR4_05": ["Was kommt als nächstes? 2, 3, 5, 8, 13, ?", "Schauen Sie sich die Unterschiede an – es folgt einem bekannten Muster.", ["21", "18", "20", "16"], "Die Differenzen betragen 1, 2, 3, 5, 8 – jede Differenz ist die Summe der beiden davor. Der nächste Unterschied ist 8, also 13 + 8 = 21."],
    "TPR4_06": ["Was kommt als nächstes? 1, 4, 10, 20, 35, ?", "Schauen Sie sich die Differenzen zweiter Ordnung an – sie erhöhen sich um 1.", ["56", "50", "48", "55"], "Differenzen erster Ordnung: 3, 6, 10, 15. Differenzen zweiter Ordnung: 3, 4, 5 → nächste 6. Nächste Differenz erster Ordnung: 21. Antwort: 35 + 21 = 56."],
    "TPR4_07": ["Was kommt als nächstes? 1, 3, 2, 6, 4, 12, 8, ?", "Unterteilt die Zeichenfolge in Begriffe an ungeraden und geraden Positionen.", ["24", "16", "10", "20"], "Ungerade Positionen: 1, 2, 4, 8 (×2). Gerade Positionen: 3, 6, 12, 24 (×2). Der nächste gerade Term ist 24."],
    "TPR4_08": ["Raster: 2, 3, 11 / 4, 5, 29 / 6, 7, ?", "Versuchen Sie es mit (Spalte1 + 1) × (Spalte2 + 1) und passen Sie es an.", ["55", "42", "48", "53"], "Spalte 3 = (Spalte 1 + 1) × (Spalte 2 + 1) − 1. Zeile 3: 7 × 8 − 1 = 55."],
    "TPR4_09": ["Was kommt als nächstes? 256, 128, 64, 32, 16, ?", "Jeder Begriff wird halbiert.", ["8", "4", "12", "10"], "Jeder Term ist durch 2 teilbar. Nach 16 ist der nächste Term 16 ÷ 2 = 8."],
    "TPR4_10": ["Raster: 1, 2, 3, 6 / 2, 3, 5, 30 / 3, 4, 7, ?", "In welcher Beziehung steht die letzte Spalte zu den ersten drei?", ["84", "14", "21", "72"], "Spalte 4 = Spalte 1 × Spalte 2 × Spalte 3. Zeile 3: 3 × 4 × 7 = 84."],
    "TPR4_11": ["Was kommt als nächstes? 2, 6, 18, 54, ?", "Jeder Term wird mit derselben Zahl multipliziert.", ["162", "108", "144", "216"], "Jeder Term wird mit 3 multipliziert. Nach 54 ist der nächste Term 54 × 3 = 162."],
    "TPR4_12": ["Was kommt als nächstes? 1, 5, 14, 30, 55, ?", "Die Unterschiede zwischen den Begriffen sind perfekte Quadrate.", ["91", "80", "85", "90"], "Die Unterschiede betragen 4, 9, 16, 25 (also 2², 3², 4², 5²). Der nächste Unterschied ist 6² = 36: 55 + 36 = 91."],
    "TPR4_13": ["Was kommt als nächstes? 1000, 500, 250, 125, ?", "Jeder Begriff wird halbiert.", ["62,5", "60", "75", "100"], "Jeder Term ist durch 2 teilbar. Nach 125 ist der nächste Term 125 ÷ 2 = 62,5."],
    "TPR4_14": ["Raster: 10, 3, 7 / 20, 8, 12 / 30, 11, ?", "Wie hängen die Spalten arithmetisch zusammen?", ["19", "20", "21", "41"], "Spalte 1 − Spalte 2 = Spalte 3. Zeile 3: 30 − 11 = 19."],
    "TPR4_15": ["Was kommt als nächstes? 4, 5, 9, 14, 23, 37, ?", "Jeder Term ist die Summe der beiden vorherigen Terme.", ["60", "51", "56", "74"], "Wie bei Fibonacci: Jeder Term = die Summe der beiden vorherigen. 23 + 37 = 60."],
    "TPR4_16": ["Raster: 2, 8, 3 / 3, 27, 8 / 4, 64, ?", "Spalte 2 ist eine Potenz von Spalte 1. Welchem ​​Muster folgt Spalte 3?", ["15", "16", "12", "20"], "Spalte 2 = Spalte 1³. Spalte 3 = Spalte 1² − 1: 2²−1=3, 3²−1=8, 4²−1=15."],
    "TPR4_17": ["Was kommt als nächstes? 1, 5, 21, 85, ?", "Versuchen Sie, jeden Term mit 4 zu multiplizieren und 1 zu addieren.", ["341", "256", "340", "345"], "Jeder Term = vorheriges × 4 + 1: 1→5, 5→21, 21→85, 85→341."],
    "TPR4_18": ["Was kommt als nächstes? 1, 2, 5, 12, 29, ?", "Jeder Begriff verwendet die beiden vorherigen mit einem Multiplikator.", ["70", "58", "65", "72"], "Regel: a(n) = 2×a(n−1) + a(n−2). Überprüfen Sie: 2×2+1=5, 2×5+2=12, 2×12+5=29, 2×29+12=70."],
    "TPR4_19": ["Raster: 3, 2, 11 / 4, 3, 19 / 5, 4, ?", "Versuchen Sie, Spalte 1 plus Spalte 2 zu quadrieren.", ["29", "20", "25", "30"], "Spalte 3 = Spalte 1² + Spalte 2. Zeile 3: 5² + 4 = 25 + 4 = 29."],
    "TPR4_20": ["Raster: 4, 3, 13 / 5, 2, 23 / 6, 1, ?", "Versuchen Sie es mit quadrierter Spalte 1 minus Spalte 2.", ["35", "30", "36", "42"], "Spalte 3 = Spalte 1² − Spalte 2. Zeile 3: 6² − 1 = 36 − 1 = 35."],
    "TPR5_01": ["Was kommt als nächstes in der Folge der Primzahlen? 23, 29, 31, 37, 41, ?", "Listen Sie die Primzahlen nach 41 auf.", ["43", "42", "45", "47"], "String listet aufeinanderfolgende Primzahlen auf. Nach 41 ist die nächste Primzahl 43."],
    "TPR5_02": ["Was kommt als nächstes? 2, 1, 3, 4, 7, 11, 18, ?", "Jeder Term ist die Summe der beiden vorherigen Terme.", ["29", "25", "27", "36"], "Lucas-Reihe: jeder Term = die Summe der beiden davor. 11 + 18 = 29."],
    "TPR5_03": ["Gitter: 2, 8, 32 / 3, 27, 243 / 5, 125, ?", "Jede Spalte verwendet eine ungerade Potenz der ersten Zahl.", ["3125", "625", "1250", "1500"], "Das Zeilenmuster ist n¹, n³, n⁵. Zeile 3: 5¹=5, 5³=125, 5⁵=3125."],
    "TPR5_04": ["Was kommt als nächstes? 4, 6, 10, 14, 22, 26, ?", "Jeder Term ist zweimal eine Primzahl. Welche Prämien?", ["34", "30", "32", "38"], "Jeder Term ist 2 × eine aufeinanderfolgende Primzahl: 2×2=4, 2×3=6, 2×5=10, 2×7=14, 2×11=22, 2×13=26, 2×17=34."],
    "TPR5_05": ["Was kommt als nächstes? 0, 0, 1, 1, 2, 4, 7, 13, ?", "Jeder Term ist die Summe der drei vorherigen Terme.", ["24", "20", "26", "19"], "Es handelt sich um die Tribonacci-Reihe: Jeder Term = die Summe der drei davor. 4 + 7 + 13 = 24."],
    "TPR5_06": ["Was kommt als nächstes? 2, 12, 36, 80, 150, ?", "Versuchen Sie, jeden Term als n²(n + 1) auszudrücken.", ["252", "210", "240", "260"], "Jeder Term ist n²(n+1): 1²×2=2, 2²×3=12, 3²×4=36, 4²×5=80, 5²×6=150, 6²×7=252."],
    "TPR5_07": ["Raster: 1, 2, 5 / 2, 3, 13 / 4, 5, ?", "Probieren Sie die Quadrate der ersten beiden hinzugefügten Spalten aus.", ["41", "20", "45", "36"], "Spalte 3 = Spalte 1² + Spalte 2². Reihe 3: 4² + 5² = 16 + 25 = 41."],
    "TPR5_08": ["Was kommt als nächstes? 2, 8, 18, 32, 50, ?", "Versuchen Sie, jeden Term für n aufeinanderfolgende Terme als 2n² auszudrücken.", ["72", "60", "68", "80"], "Jeder Term ist 2n²: 2(1²)=2, 2(2²)=8, 2(3²)=18, 2(4²)=32, 2(5²)=50, 2(6²)=72."],
    "TPR5_09": ["Was kommt als nächstes? 2, 4, 16, 256, ?", "Jeder Term ist das Quadrat des vorherigen Termes.", ["65536", "512", "1024", "4096"], "Jeder Term = vorheriger². 2²=4, 4²=16, 16²=256, 256²=65536."],
    "TPR5_10": ["Was kommt als nächstes? 47, 43, 41, 37, 31, 29, ?", "Es sind Primzahlen in absteigender Reihenfolge.", ["23", "27", "25", "19"], "String listet aufeinanderfolgende Primzahlen in absteigender Reihenfolge auf. Nach 29 ist die nächstkleinere Primzahl 23."],
    "TPR5_11": ["Raster: 2, 3, 7 / 4, 5, 21 / 6, 7, ?", "Multiplizieren Sie die ersten beiden Spalten und passen Sie sie um 1 an.", ["43", "42", "44", "40"], "Spalte 3 = Spalte 1 × Spalte 2 + 1. Zeile 3: 6 × 7 + 1 = 43."],
    "TPR5_12": ["Was kommt als nächstes? 1, 5, 12, 22, 35, ?", "Dies sind fünfeckige Zahlen: n(3n − 1)/2.", ["51", "48", "50", "55"], "Fünfeckige Zahlen: n(3n−1)/2. Für n=6: 6×17/2 = 51."],
    "TPR5_13": ["Was kommt als nächstes? 2, 6, 30, 210, ?", "Jeder Term wird mit der nächsten Primzahl multipliziert.", ["2310", "1470", "1260", "1890"], "2×3=6, 6×5=30, 30×7=210, 210×11=2310. Bei jedem Schritt multiplizieren Sie mit der nächsten Primzahl."],
    "TPR5_14": ["Gitter: 4, 16, 64 / 6, 36, 216 / 8, 64, ?", "Jede Zeile zeigt Potenzen der ersten Zahl.", ["512", "256", "480", "128"], "Das Zeilenmuster ist n¹, n², n³. Reihe 3: 8, 64, 512."],
    "TPR5_15": ["Was kommt als nächstes? 1, 3, 11, 43, ?", "Jeder Term wird mit 4 multipliziert und um 1 verringert.", ["171", "170", "172", "160"], "Jeder Term = vorheriges × 4 − 1: 1→3, 3→11, 11→43, 43→171."],
    "TPR5_16": ["Was kommt als nächstes? 59, 53, 47, 43, 41, 37, ?", "Dies sind Primzahlen in absteigender Reihenfolge.", ["31", "33", "29", "35"], "String listet aufeinanderfolgende Primzahlen in umgekehrter Reihenfolge auf. Nach 37 ist die nächstkleinere Primzahl 31."],
    "TPR5_17": ["Was kommt als nächstes? 27, 125, 343, 729, ?", "Jeder Term ist ein Würfel – wessen Zahlen?", ["1331", "1000", "1200", "1500"], "Dies sind Würfel aus aufeinanderfolgenden ungeraden Zahlen: 3³=27, 5³=125, 7³=343, 9³=729, 11³=1331."],
    "TPR5_18": ["Raster: 3, 2, 18 / 4, 3, 48 / 5, 4, ?", "Versuchen Sie, Spalte1 mit Spalte2 zu quadrieren.", ["100", "80", "60", "125"], "Spalte 3 = Spalte 1² × Spalte 2. Zeile 3: 5² × 4 = 25 × 4 = 100."],
    "TPR5_19": ["Was kommt als nächstes? 2, 3, 6, 7, 14, 15, ?", "Die Zeichenfolge wechselt zwischen zwei Vorgängen.", ["30", "16", "28", "22"], "Das Muster wechselt +1 und ×2: 2+1=3, 3×2=6, 6+1=7, 7×2=14, 14+1=15, 15×2=30."],
    "TPR5_20": ["Was kommt als nächstes? 1, 9, 36, 100, 225, ?", "Jeder Term ist ein perfektes Quadrat. Auf welche Zahlen werden sie angehoben?", ["441", "400", "484", "500"], "Dies sind Quadrate kumulativer Summen: (1)²=1, (1+2)²=9, (1+2+3)²=36, (1+2+3+4)²=100, (1+2+3+4+5)²=225, (1+2+3+4+5+6)²=441."],
    "TNR1_01": ["Was kommt als nächstes in der Zeichenfolge: 7, 8, 9, 10, 11, ?", "Schauen Sie sich den Unterschied zwischen jedem Paar aufeinanderfolgender Begriffe an.", ["12", "13", "10", "14"], "Jeder Term erhöht sich um 1. Der nächste Term ist 11 + 1 = 12."],
    "TNR1_02": ["Was kommt als nächstes in der Zeichenfolge: 3, 5, 7, 9, 11, ?", "Subtrahieren Sie jeden Term vom nächsten.", ["13", "12", "14", "15"], "Jeder Term erhöht sich um 2. Der nächste Term ist 11 + 2 = 13."],
    "TNR1_03": ["Was kommt als nächstes in der Zeichenfolge: 10, 13, 16, 19, 22, ?", "Ermittelt die konstante Differenz zwischen aufeinanderfolgenden Termen.", ["25", "24", "26", "23"], "Jeder Term erhöht sich um 3. Der nächste Term ist 22 + 3 = 25."],
    "TNR1_04": ["Was kommt als nächstes in der Zeichenfolge: 1, 5, 9, 13, 17, ?", "Um wie viel erhöht sich jeder Begriff gegenüber dem vorherigen?", ["21", "20", "22", "19"], "Jeder Term erhöht sich um 4. Der nächste Term ist 17 + 4 = 21."],
    "TNR1_05": ["Was kommt als nächstes in der Zeichenfolge: 2, 7, 12, 17, 22, ?", "Berechnet den Schritt zwischen aufeinanderfolgenden Termen.", ["27", "25", "28", "26"], "Jeder Term erhöht sich um 5. Der nächste Term ist 22 + 5 = 27."],
    "TNR1_06": ["Was kommt als nächstes in der Zeichenfolge: 4, 10, 16, 22, 28, ?", "Was wird jedes Mal hinzugefügt?", ["34", "32", "36", "30"], "Jeder Term erhöht sich um 6. Der nächste Term ist 28 + 6 = 34."],
    "TNR1_07": ["Was kommt als nächstes in der Zeichenfolge: 3, 10, 17, 24, 31, ?", "Finden Sie die zu jedem Term hinzugefügte Konstante.", ["38", "35", "39", "37"], "Jeder Term erhöht sich um 7. Der nächste Term ist 31 + 7 = 38."],
    "TNR1_08": ["Was kommt als nächstes in der Zeichenfolge: 5, 13, 21, 29, 37, ?", "Subtrahieren Sie den ersten Term vom zweiten, um die Schrittgröße zu ermitteln.", ["45", "44", "46", "43"], "Jeder Term erhöht sich um 8. Der nächste Term ist 37 + 8 = 45."],
    "TNR1_09": ["Was kommt als nächstes in der Zeichenfolge: 2, 11, 20, 29, 38, ?", "Welche Zahl wird jedem Schritt hinzugefügt?", ["47", "45", "48", "46"], "Jeder Term erhöht sich um 9. Der nächste Term ist 38 + 9 = 47."],
    "TNR1_10": ["Was kommt als nächstes in der Zeichenfolge: 6, 16, 26, 36, 46, ?", "Schauen Sie sich das Intervall zwischen zwei aufeinanderfolgenden Begriffen an.", ["56", "54", "58", "52"], "Jeder Term erhöht sich um 10. Der nächste Term ist 46 + 10 = 56."],
    "TNR1_11": ["Was kommt als nächstes in der Zeichenfolge: 20, 19, 18, 17, 16, ?", "Die Saite nimmt ab. Wie viel pro Schritt?", ["15", "14", "17", "13"], "Jeder Term verringert sich um 1. Der nächste Term ist 16 − 1 = 15."],
    "TNR1_12": ["Was kommt als nächstes in der Zeichenfolge: 30, 28, 26, 24, 22, ?", "Subtrahieren Sie jeden Term von dem davor.", ["20", "21", "18", "19"], "Jeder Term verringert sich um 2. Der nächste Term ist 22 − 2 = 20."],
    "TNR1_13": ["Was kommt als nächstes in der Zeichenfolge: 40, 37, 34, 31, 28, ?", "Die Saite nimmt ab. Finden Sie Ihr gleichmäßiges Tempo.", ["25", "26", "24", "27"], "Jeder Term verringert sich um 3. Der nächste Term ist 28 − 3 = 25."],
    "TNR1_14": ["Was kommt als nächstes in der Zeichenfolge: 50, 46, 42, 38, 34, ?", "Wie stark nimmt es jedes Mal ab?", ["30", "32", "28", "31"], "Jeder Term verringert sich um 4. Der nächste Term ist 34 − 4 = 30."],
    "TNR1_15": ["Was kommt als nächstes in der Zeichenfolge: 60, 55, 50, 45, 40, ?", "Findet das niedrigste Maß zwischen aufeinanderfolgenden Termen.", ["35", "30", "38", "33"], "Jeder Term verringert sich um 5. Der nächste Term ist 40 − 5 = 35."],
    "TNR1_16": ["Was kommt als nächstes in der Zeichenfolge: 5, 16, 27, 38, 49, ?", "Berechnen Sie die Differenz zwischen den ersten beiden Termen und prüfen Sie, ob sie gleich bleibt.", ["60", "58", "61", "55"], "Jeder Term erhöht sich um 11. Der nächste Term ist 49 + 11 = 60."],
    "TNR1_17": ["Was kommt als nächstes in der Zeichenfolge: 3, 15, 27, 39, 51, ?", "Welche Konstante wird bei jedem Schritt hinzugefügt?", ["63", "60", "64", "62"], "Jeder Term erhöht sich um 12. Der nächste Term ist 51 + 12 = 63."],
    "TNR1_18": ["Was kommt als nächstes in der Zeichenfolge: 10, 25, 40, 55, 70, ?", "Findet die feste Tonhöhe, die zwischen den Begriffen hinzugefügt wird.", ["85", "80", "90", "75"], "Jeder Term erhöht sich um 15. Der nächste Term ist 70 + 15 = 85."],
    "TNR1_19": ["Was kommt als nächstes in der Zeichenfolge: 5, 25, 45, 65, 85, ?", "Berechnet die Schrittgröße von einem Term zum nächsten.", ["105", "100", "110", "95"], "Jeder Term erhöht sich um 20. Der nächste Term ist 85 + 20 = 105."],
    "TNR1_20": ["Was kommt als nächstes in der Zeichenfolge: 42, 36, 30, 24, 18, ?", "Die Saite nimmt ab. Was wird jeweils abgezogen?", ["12", "14", "10", "16"], "Jeder Term verringert sich um 6. Der nächste Term ist 18 − 6 = 12."],
    "TNR2_01": ["Was kommt als nächstes in der Zeichenfolge: 5, 10, 20, 40, 80, ?", "Versuchen Sie, jeden Term durch den vorherigen zu dividieren.", ["160", "120", "140", "100"], "Jeder Term wird mit 2 multipliziert. Der nächste Term ist 80 × 2 = 160."],
    "TNR2_02": ["Was kommt als nächstes in der Zeichenfolge: 2, 6, 18, 54, 162, ?", "Wie groß ist das Verhältnis aufeinanderfolgender Terme?", ["486", "324", "480", "648"], "Jeder Term wird mit 3 multipliziert. Der nächste Term ist 162 × 3 = 486."],
    "TNR2_03": ["Was kommt als nächstes in der Zeichenfolge: 1, 4, 16, 64, 256, ?", "Teilen Sie den zweiten Term durch den ersten, um den Multiplikator zu ermitteln.", ["1024", "512", "768", "1280"], "Jeder Term wird mit 4 multipliziert. Der nächste Term ist 256 × 4 = 1024."],
    "TNR2_04": ["Was kommt als nächstes in der Zeichenfolge: 2, 10, 50, 250, 1250, ?", "Schauen Sie sich das Verhältnis aufeinanderfolgender Begriffe an.", ["6250", "5000", "6000", "7500"], "Jeder Term wird mit 5 multipliziert. Der nächste Term ist 1250 × 5 = 6250."],
    "TNR2_05": ["Was kommt als nächstes in der Zeichenfolge: 3, 30, 300, 3000, 30000, ?", "Jeder Term erhält eine weitere Null. Womit multipliziert es sich?", ["300000", "60000", "200000", "330000"], "Jeder Term wird mit 10 multipliziert. Der nächste Term ist 30000 × 10 = 300000."],
    "TNR2_06": ["Was kommt als nächstes in der Zeichenfolge: 640, 320, 160, 80, 40, ?", "Die Saite wird halbiert. Welche Operation wird bei jedem Schritt angewendet?", ["20", "10", "30", "25"], "Jeder Term ist durch 2 teilbar. Der nächste Term ist 40 ÷ 2 = 20."],
    "TNR2_07": ["Was kommt als nächstes in der Zeichenfolge: 729, 243, 81, 27, 9, ?", "Versuchen Sie, jeden Begriff in den nächsten aufzuteilen.", ["3", "6", "1", "4"], "Jeder Term ist durch 3 teilbar. Der nächste Term ist 9 ÷ 3 = 3."],
    "TNR2_08": ["Was kommt als nächstes in der Zeichenfolge: 192, 96, 48, 24, 12, ?", "Welcher Bruchteil des vorherigen Termes ergibt den aktuellen Term?", ["6", "4", "8", "3"], "Jeder Term ist durch 2 teilbar. Der nächste Term ist 12 ÷ 2 = 6."],
    "TNR2_09": ["Was kommt als nächstes in der Zeichenfolge: 3, 4, 7, 11, 18, ?", "Versuchen Sie, zwei aufeinanderfolgende Begriffe hinzuzufügen.", ["29", "25", "27", "30"], "Jeder Term ist die Summe der beiden davor: 11 + 18 = 29."],
    "TNR2_10": ["Was kommt als nächstes in der Zeichenfolge: 2, 5, 7, 12, 19, ?", "Schauen Sie sich an, wie sich jeder Begriff auf die beiden davor bezieht.", ["31", "26", "28", "33"], "Jeder Term ist die Summe der beiden davor: 12 + 19 = 31."],
    "TNR2_11": ["Was kommt als nächstes in der Zeichenfolge: 4, 9, 19, 39, 79, ?", "Versuchen Sie, einen Term zu verdoppeln und ihn dann um eine kleine Zahl anzupassen.", ["159", "158", "160", "149"], "Jeder Term folgt der Regel: vorheriger × 2 + 1. Der nächste Term ist 79 × 2 + 1 = 159."],
    "TNR2_12": ["Was kommt als nächstes in der Zeichenfolge: 4, 12, 36, 108, 324, ?", "Teilen Sie jeden Term durch den vorherigen Term, um ein konstantes Verhältnis zu finden.", ["972", "648", "1296", "900"], "Jeder Term wird mit 3 multipliziert. Der nächste Term ist 324 × 3 = 972."],
    "TNR2_13": ["Was kommt als nächstes in der Zeichenfolge: 7, 14, 28, 56, 112, ?", "Was passiert, wenn Sie jeden Begriff durch den davor liegenden Begriff dividieren?", ["224", "168", "220", "228"], "Jeder Term wird mit 2 multipliziert. Der nächste Term ist 112 × 2 = 224."],
    "TNR2_14": ["Was kommt als nächstes in der Zeichenfolge: 1, 3, 4, 7, 11, ?", "Überprüfen Sie, ob jeder Term die Summe der beiden davor ist.", ["18", "15", "16", "20"], "Jeder Term ist die Summe der beiden davor: 7 + 11 = 18."],
    "TNR2_15": ["Was kommt als nächstes in der Zeichenfolge: 256, 128, 64, 32, 16, ?", "Das sind alles Potenzen von 2. Welcher Teiler verbindet jedes Paar?", ["8", "4", "12", "10"], "Jeder Term ist durch 2 teilbar. Der nächste Term ist 16 ÷ 2 = 8."],
    "TNR2_16": ["Was kommt als nächstes in der Zeichenfolge: 1, 5, 25, 125, 625, ?", "Finden Sie den Multiplikator, indem Sie einen beliebigen Term durch den vorherigen Term dividieren.", ["3125", "1250", "3000", "3750"], "Jeder Term wird mit 5 multipliziert. Der nächste Term ist 625 × 5 = 3125."],
    "TNR2_17": ["Was kommt als nächstes in der Zeichenfolge: 3, 8, 18, 38, 78, ?", "Versuchen Sie, den vorherigen Term zu verdoppeln und eine kleine Konstante hinzuzufügen.", ["158", "156", "160", "148"], "Jeder Term folgt der Regel: vorheriger × 2 + 2. Der nächste Term ist 78 × 2 + 2 = 158."],
    "TNR2_18": ["Was kommt als nächstes in der Zeichenfolge: 1, 4, 5, 9, 14, ?", "Prüfen Sie, ob die Summe zweier aufeinanderfolgender Terme Folgendes ergibt.", ["23", "19", "21", "25"], "Jeder Term ist die Summe der beiden davor: 9 + 14 = 23."],
    "TNR2_19": ["Was kommt als nächstes in der Zeichenfolge: 2187, 729, 243, 81, 27, ?", "Jeder Begriff ist ein Bruchteil des vorherigen. Welcher Teiler wird verwendet?", ["9", "3", "18", "12"], "Jeder Term ist durch 3 teilbar. Der nächste Term ist 27 ÷ 3 = 9."],
    "TNR2_20": ["Was kommt als nächstes in der Zeichenfolge: 2, 8, 32, 128, 512, ?", "Teilen Sie aufeinanderfolgende Terme, um den konstanten Multiplikator zu ermitteln.", ["2048", "1024", "2560", "1536"], "Jeder Term wird mit 4 multipliziert. Der nächste Term ist 512 × 4 = 2048."],
    "TNR3_01": ["Was kommt als nächstes in der Zeichenfolge: 36, 49, 64, 81, 100, ?", "Versuchen Sie es mit der Quadratwurzel jedes Termes.", ["121", "110", "120", "125"], "Es handelt sich um aufeinanderfolgende perfekte Quadrate: 6²=36, 7²=49, 8²=64, 9²=81, 10²=100, 11²=121."],
    "TNR3_02": ["Was kommt als nächstes in der Zeichenfolge: 100, 121, 144, 169, 196, ?", "Jeder Term ist ein perfektes Quadrat. Welche Quadrate sind das?", ["225", "220", "230", "216"], "Es handelt sich um aufeinanderfolgende perfekte Quadrate: 10²=100, 11²=121, 12²=144, 13²=169, 14²=196, 15²=225."],
    "TNR3_03": ["Was kommt als nächstes in der Zeichenfolge: 125, 216, 343, 512, 729, ?", "Versuchen Sie es mit der Kubikwurzel jedes Termes.", ["1000", "900", "1024", "972"], "Es handelt sich um aufeinanderfolgende perfekte Würfel: 5³=125, 6³=216, 7³=343, 8³=512, 9³=729, 10³=1000."],
    "TNR3_04": ["Was kommt als nächstes in der Zeichenfolge: 343, 512, 729, 1000, 1331, ?", "Dies sind Würfel aus aufeinanderfolgenden ganzen Zahlen. Welche ganzen Zahlen?", ["1728", "1500", "1700", "2000"], "Es handelt sich um aufeinanderfolgende perfekte Würfel: 7³=343, 8³=512, 9³=729, 10³=1000, 11³=1331, 12³=1728."],
    "TNR3_05": ["Was kommt als nächstes in der Zeichenfolge: 10, 12, 16, 22, 30, ?", "Berechnen Sie die Unterschiede zwischen den Begriffen. Bilden diese Unterschiede ein Muster?", ["40", "38", "42", "36"], "Die Unterschiede betragen 2, 4, 6, 8 – bei jedem Schritt erhöhen sie sich um 2. Die nächste Differenz beträgt 10, also 30 + 10 = 40."],
    "TNR3_06": ["Was kommt als nächstes in der Zeichenfolge: 7, 10, 16, 25, 37, ?", "Finden Sie die Unterschiede zwischen den Begriffen und suchen Sie dann nach einem Muster in diesen Unterschieden.", ["52", "49", "55", "46"], "Die Unterschiede betragen 3, 6, 9, 12 – bei jedem Schritt erhöhen sie sich um 3. Die nächste Differenz beträgt 15, also 37 + 15 = 52."],
    "TNR3_07": ["Was kommt als nächstes in der Zeichenfolge: 5, 6, 9, 14, 21, ?", "Die Unterschiede zwischen den Begriffen sind aufeinanderfolgende ungerade Zahlen.", ["30", "28", "32", "27"], "Die Unterschiede sind 1, 3, 5, 7 – aufeinanderfolgende ungerade Zahlen. Der nächste Unterschied ist 9, also 21 + 9 = 30."],
    "TNR3_08": ["Was kommt als nächstes in der Zeichenfolge: 5, 7, 11, 13, 17, ?", "Stellen Sie sich Zahlen vor, die genau zwei Teiler haben.", ["19", "18", "21", "20"], "Es handelt sich um aufeinanderfolgende Primzahlen, die bei 5 beginnen. Die nächste Primzahl nach 17 ist 19."],
    "TNR3_09": ["Was kommt als nächstes in der Zeichenfolge: 11, 13, 17, 19, 23, ?", "Sind diese Zahlen nur durch 1 und sich selbst teilbar?", ["29", "27", "25", "31"], "Es handelt sich um aufeinanderfolgende Primzahlen, die bei 11 beginnen. Die nächste Primzahl nach 23 ist 29."],
    "TNR3_10": ["Was kommt als nächstes in der Zeichenfolge: 4, 16, 36, 64, 100, ?", "Extrahieren Sie die Quadratwurzel jedes Termes. Was haben diese Zahlen gemeinsam?", ["144", "128", "136", "148"], "Dies sind Quadrate aufeinanderfolgender gerader Zahlen: 2²=4, 4²=16, 6²=36, 8²=64, 10²=100, 12²=144."],
    "TNR3_11": ["Was kommt als nächstes in der Zeichenfolge: 1, 9, 25, 49, 81, ?", "Extrahieren Sie die Quadratwurzel jedes Termes. Um welche Art von Zahlen handelt es sich?", ["121", "100", "110", "125"], "Dies sind Quadrate aufeinanderfolgender ungerader Zahlen: 1²=1, 3²=9, 5²=25, 7²=49, 9²=81, 11²=121."],
    "TNR3_12": ["Was kommt als nächstes in der Zeichenfolge: 2, 5, 10, 17, 26, ?", "Subtrahiere 1 von jedem Term. Kommen Ihnen die Ergebnisse bekannt vor?", ["37", "35", "36", "39"], "Jeder Term ist n² + 1: 1²+1=2, 2²+1=5, 3²+1=10, 4²+1=17, 5²+1=26, 6²+1=37."],
    "TNR3_13": ["Was kommt als nächstes in der Zeichenfolge: 0, 3, 8, 15, 24, ?", "Addiere zu jedem Begriff 1. Welche bekannte Saite bekommst du?", ["35", "33", "36", "30"], "Jeder Term ist n² − 1: 1²−1=0, 2²−1=3, 3²−1=8, 4²−1=15, 5²−1=24, 6²−1=35."],
    "TNR3_14": ["Was kommt als nächstes in der Zeichenfolge: 5, 9, 17, 29, 45, ?", "Berechnen Sie die Unterschiede und prüfen Sie dann, ob sie regelmäßig zunehmen.", ["65", "61", "69", "57"], "Die Unterschiede betragen 4, 8, 12, 16 – bei jedem Schritt erhöhen sie sich um 4. Die nächste Differenz beträgt 20, also 45 + 20 = 65."],
    "TNR3_15": ["Was kommt als nächstes in der Zeichenfolge: 2, 9, 28, 65, 126, ?", "Subtrahiere 1 von jedem Term. Welche Zahlen bleiben übrig?", ["217", "215", "220", "210"], "Jeder Term ist n³ + 1: 1³+1=2, 2³+1=9, 3³+1=28, 4³+1=65, 5³+1=126, 6³+1=217."],
    "TNR3_16": ["Was kommt als nächstes in der Zeichenfolge: 3, 8, 15, 24, 35, ?", "Versuchen Sie, jeden Term als Produkt zweier benachbarter Zahlen auszudrücken.", ["48", "46", "50", "44"], "Jeder Term ist n(n + 2): 1×3=3, 2×4=8, 3×5=15, 4×6=24, 5×7=35, 6×8=48."],
    "TNR3_17": ["What comes next in the string: 1, 5, 11, 19, 29, ?", "The differences between the terms increase with a constant. Finden Sie diese Konstante.", ["41", "39", "43", "37"], "The differences are 4, 6, 8, 10 — increasing by 2 at each step. Die nächste Differenz beträgt 12, also 29 + 12 = 41."],
    "TNR3_18": ["Was kommt als nächstes in der Zeichenfolge: 2, 8, 18, 32, 50, ?", "Versuchen Sie, jeden Begriff durch 2 zu dividieren. Kommen Ihnen die Ergebnisse bekannt vor?", ["72", "68", "74", "64"], "Jeder Term ist 2n²: 2(1²)=2, 2(2²)=8, 2(3²)=18, 2(4²)=32, 2(5²)=50, 2(6²)=72."],
    "TNR3_19": ["Was kommt als nächstes in der Zeichenfolge: 4, 7, 12, 19, 28, ?", "Subtrahiere 3 von jedem Term. Welche Saite erkennst du?", ["39", "37", "41", "36"], "Jeder Term ist n² + 3: 1²+3=4, 2²+3=7, 3²+3=12, 4²+3=19, 5²+3=28, 6²+3=39."],
    "TNR3_20": ["Was kommt als nächstes in der Zeichenfolge: 4, 9, 19, 34, 54, ?", "Finden Sie die Unterschiede und dann die Unterschiede dieser Unterschiede.", ["79", "74", "84", "69"], "Die Unterschiede betragen 5, 10, 15, 20 – bei jedem Schritt erhöhen sie sich um 5. Die nächste Differenz beträgt 25, also 54 + 25 = 79."],
    "TNR4_01": ["Was kommt als nächstes in der Zeichenfolge: 2, 3, 7, 25, 121, ?", "Subtrahieren Sie 1 von jedem Term und prüfen Sie, ob Sie die Zahlen erkennen.", ["721", "720", "625", "719"], "Jeder Term ist n! + 1: 1!+1=2, 2!+1=3, 3!+1=7, 4!+1=25, 5!+1=121, 6!+1=721."],
    "TNR4_02": ["Was kommt als nächstes in der Zeichenfolge: 0, 1, 5, 23, 119, ?", "Addiere zu jedem Begriff 1. Erkennen Sie die resultierenden Zahlen?", ["719", "720", "600", "721"], "Jeder Term ist n! − 1: 1!−1=0, 2!−1=1, 3!−1=5, 4!−1=23, 5!−1=119, 6!−1=719."],
    "TNR4_03": ["Was kommt als nächstes in der Zeichenfolge: 15, 21, 28, 36, 45, ?", "Das sind Dreieckszahlen. Die Differenzen zwischen den Termen erhöhen sich bei jedem Schritt um 1.", ["55", "54", "56", "50"], "Dreieckszahlen T(5)–T(10). Die Unterschiede betragen 6, 7, 8, 9, also ist der nächste 10: 45 + 10 = 55."],
    "TNR4_04": ["Was kommt als nächstes in der Zeichenfolge: 36, 45, 55, 66, 78, ?", "Berechnen Sie die Unterschiede. Sie erhöhen sich jedes Mal um 1 – Vorzeichen der Dreieckszahlen.", ["91", "88", "90", "84"], "Dreieckszahlen T(8)–T(13). Die Unterschiede sind 9, 10, 11, 12, also ist der nächste 13: 78 + 13 = 91."],
    "TNR4_05": ["Was kommt als nächstes in der Zeichenfolge: 1, 5, 13, 29, 61, ?", "Versuchen Sie, den vorherigen Term zu verdoppeln und eine kleine Konstante hinzuzufügen.", ["125", "122", "123", "127"], "Jeder Term folgt der Regel: vorheriger × 2 + 3. Der nächste Term ist 61 × 2 + 3 = 125."],
    "TNR4_06": ["Was kommt als nächstes in der Zeichenfolge: 1, 2, 5, 14, 41, ?", "Versuchen Sie, den vorherigen Term mit 3 zu multiplizieren und anzupassen.", ["122", "120", "123", "82"], "Jeder Term folgt der Regel: vorheriger × 3 − 1. Der nächste Term ist 41 × 3 − 1 = 122."],
    "TNR4_07": ["Was kommt als nächstes in der Zeichenfolge: 2, 9, 23, 51, 107, ?", "Verdoppeln Sie den vorherigen Term und fügen Sie eine Konstante hinzu, um den nächsten zu erhalten.", ["219", "214", "215", "221"], "Jeder Term folgt der Regel: vorheriger × 2 + 5. Der nächste Term ist 107 × 2 + 5 = 219."],
    "TNR4_08": ["Was kommt als nächstes in der Zeichenfolge: 9, 25, 49, 121, 169, ?", "Ziehen Sie die Quadratwurzel jedes Termes und überlegen Sie dann, was das Besondere an diesen Zahlen ist.", ["289", "225", "256", "324"], "Dies sind Quadrate aufeinanderfolgender Primzahlen: 3²=9, 5²=25, 7²=49, 11²=121, 13²=169, 17²=289."],
    "TNR4_09": ["Was kommt als nächstes in der Zeichenfolge: 10, 11, 15, 24, 40, ?", "Finden Sie die Unterschiede zwischen den Begriffen. Sind diese Unterschiede eine bekannte Zeichenfolge?", ["65", "56", "64", "60"], "Die Unterschiede sind 1, 4, 9, 16 – perfekte Quadrate (1², 2², 3², 4²). Der nächste Unterschied ist 5²=25, also 40 + 25 = 65."],
    "TNR4_10": ["Was kommt als nächstes in der Zeichenfolge: 0, 1, 3, 9, 33, ?", "Berechnen Sie die Unterschiede zwischen den Begriffen. Erinnern sie Sie an eine berühmte Zeile?", ["153", "129", "150", "57"], "Die Unterschiede betragen 1, 2, 6, 24 – also faktoriell (1!, 2!, 3!, 4!). Der nächste Unterschied ist 5!=120, also 33 + 120 = 153."],
    "TNR4_11": ["Was kommt als nächstes in der Zeichenfolge: 2, 7, 22, 67, 202, ?", "Multiplizieren Sie den vorherigen Term mit einer Zahl und fügen Sie eine Konstante hinzu.", ["607", "606", "605", "610"], "Jeder Term folgt der Regel: vorheriger × 3 + 1. Der nächste Term ist 202 × 3 + 1 = 607."],
    "TNR4_12": ["Was kommt als nächstes in der Zeichenfolge: 20, 37, 71, 139, 275, ?", "Versuchen Sie, den vorherigen Term zu verdoppeln und eine kleine Konstante zu subtrahieren.", ["547", "550", "545", "553"], "Jeder Term folgt der Regel: vorheriger × 2 − 3. Der nächste Term ist 275 × 2 − 3 = 547."],
    "TNR4_13": ["Was kommt als nächstes in der Zeichenfolge: 1, 5, 14, 30, 55, ?", "Die Unterschiede zwischen den Begriffen sind perfekte Quadrate. Fügen Sie aufeinanderfolgende Quadrate hinzu.", ["91", "85", "90", "80"], "Dies sind kumulative Quadratsummen: 1, 1+4=5, 5+9=14, 14+16=30, 30+25=55, 55+36=91."],
    "TNR4_14": ["Was kommt als nächstes in der Zeichenfolge: 2, 4, 12, 48, 240, ?", "Versuchen Sie, jeden Term durch 2 zu dividieren. Erscheinen die Ergebnisse faktoriell?", ["1440", "1200", "1680", "960"], "Jeder Term ist 2 × n!: 2×1!=2, 2×2!=4, 2×3!=12, 2×4!=48, 2×5!=240, 2×6!=1440."],
    "TNR4_15": ["Was kommt als nächstes in der Zeichenfolge: 6, 13, 27, 55, 111, ?", "Verdoppeln Sie den vorherigen Term und fügen Sie bei jedem Schritt eine Konstante hinzu.", ["223", "222", "220", "225"], "Jeder Term folgt der Regel: vorheriger × 2 + 1. Der nächste Term ist 111 × 2 + 1 = 223."],
    "TNR4_16": ["Was kommt als nächstes in der Zeichenfolge: 10, 11, 14, 20, 30, ?", "Die Unterschiede zwischen den Begriffen sind Dreieckszahlen: 1, 3, 6, 10, …", ["45", "40", "42", "50"], "Die Unterschiede sind 1, 3, 6, 10 – Dreieckszahlen. Die nächste Dreieckszahl ist 15, also 30 + 15 = 45."],
    "TNR4_17": ["Was kommt als nächstes in der Zeichenfolge: 12, 20, 30, 42, 56, ?", "Versuchen Sie, jeden Term als Produkt zweier aufeinanderfolgender Ganzzahlen auszudrücken.", ["72", "68", "70", "64"], "Dies sind n(n+1) längliche Zahlen: 3×4=12, 4×5=20, 5×6=30, 6×7=42, 7×8=56, 8×9=72."],
    "TNR4_18": ["Was kommt als nächstes in der Zeichenfolge: 1, 9, 36, 100, 225, ?", "Jeder Term ist das Quadrat einer Dreieckszahl oder äquivalent die kumulative Kubiksumme.", ["441", "400", "440", "450"], "Dies sind Summen aufeinanderfolgender Würfel: 1³=1, 1+8=9, 9+27=36, 36+64=100, 100+125=225, 225+216=441."],
    "TNR4_19": ["Was kommt als nächstes in der Zeichenfolge: 3, 7, 19, 55, 163, ?", "Multiplizieren Sie den vorherigen Term mit einer Zahl und subtrahieren Sie eine Konstante.", ["487", "489", "485", "492"], "Jeder Term folgt der Regel: vorheriger × 3 − 2. Der nächste Term ist 163 × 3 − 2 = 487."],
    "TNR4_20": ["Was kommt als nächstes in der Zeichenfolge: 12, 23, 45, 89, 177, ?", "Verdoppeln Sie die vorherige Laufzeit und nehmen Sie eine kleine Anpassung vor.", ["353", "354", "355", "350"], "Jeder Term folgt der Regel: vorheriger × 2 − 1. Der nächste Term ist 177 × 2 − 1 = 353."],
    "TNR5_01": ["Was kommt als nächstes in der Zeichenfolge: 1, 2, 9, 64, 625, ?", "Überlegen Sie, wie viel Kraft die Basis aus jeder Position anhebt.", ["7776", "7774", "7200", "3125"], "Jeder Term ist n hoch (n−1): 1⁰=1, 2¹=2, 3²=9, 4³=64, 5⁴=625, 6⁵=7776."],
    "TNR5_02": ["Was kommt als nächstes in der Zeichenfolge: 2, 10, 30, 68, 130, ?", "Versuchen Sie, jeden Term in einen kubischen Teil und einen linearen Teil aufzuteilen.", ["222", "220", "218", "216"], "Jeder Term ist n³ + n: 1+1=2, 8+2=10, 27+3=30, 64+4=68, 125+5=130, 216+6=222."],
    "TNR5_03": ["Was kommt als nächstes in der Zeichenfolge: 1, 1, 2, 5, 14, ?", "Das sind die katalanischen Zahlen. Jedes C(n) = C(0)C(n−1) + C(1)C(n−2) + … + C(n−1)C(0).", ["42", "28", "35", "48"], "Katalanische Zahlen: C(0)=1, C(1)=1, C(2)=2, C(3)=5, C(4)=14, C(5)=42."],
    "TNR5_04": ["Was kommt als nächstes in der Zeichenfolge: 1, 5, 12, 22, 35, ?", "Die Unterschiede sind 4, 7, 10, 13 – arithmetische Progression um Schritt 3.", ["51", "48", "50", "55"], "Dies sind fünfeckige Zahlen: n(3n−1)/2. Für n=6: 6×17/2 = 51."],
    "TNR5_05": ["Was kommt als nächstes in der Zeichenfolge: 2, 5, 13, 35, 97, ?", "Versuchen Sie, jeden Term als Summe zweier Exponentialfunktionen auszudrücken.", ["275", "265", "270", "280"], "Jeder Term ist 2ⁿ + 3ⁿ (beginnend bei n=0): 1+1=2, 2+3=5, 4+9=13, 8+27=35, 16+81=97, 32+243=275."],
    "TNR5_06": ["Was kommt als nächstes in der Zeichenfolge: 1, 5, 17, 53, 161, ?", "Multiplizieren Sie den vorherigen Term mit 3 und fügen Sie eine kleine Konstante hinzu.", ["485", "483", "322", "487"], "Jeder Term folgt der Regel: vorheriger × 3 + 2. Der nächste Term ist 161 × 3 + 2 = 485."],
    "TNR5_07": ["Was kommt als nächstes in der Zeichenfolge: 1, 2, 5, 12, 27, ?", "Denken Sie an Zweierpotenzen und subtrahieren Sie dann etwas, das von der Position abhängt.", ["58", "54", "56", "60"], "Jeder Term ist 2ⁿ − n: 2¹−1=1, 2²−2=2, 2³−3=5, 2⁴−4=12, 2⁵−5=27, 2⁶−6=58."],
    "TNR5_08": ["Was kommt als nächstes in der Zeichenfolge: 2, 12, 36, 80, 150, ?", "Versuchen Sie, jeden Term als n² multipliziert mit etwas zu faktorisieren.", ["252", "240", "250", "260"], "Jeder Term ist n²(n+1): 1×2=2, 4×3=12, 9×4=36, 16×5=80, 25×6=150, 36×7=252."],
    "TNR5_09": ["Was kommt als nächstes in der Zeichenfolge: 1, 6, 15, 28, 45, ?", "Die Unterschiede betragen 5, 9, 13, 17 – Erhöhung um 4. Dies sind Hexadezimalzahlen.", ["66", "60", "63", "70"], "Sechseckige Zahlen: n(2n−1). Für n=6: 6×11 = 66."],
    "TNR5_10": ["Was kommt als nächstes in der Zeichenfolge: 2, 6, 15, 40, 145, ?", "Versuchen Sie, jeden Term in einen faktoriellen und einen quadratischen Teil aufzuteilen.", ["756", "750", "745", "760"], "Jeder Term ist n! + n²: 1!+1=2, 2!+4=6, 3!+9=15, 4!+16=40, 5!+25=145, 6!+36=756."],
    "TNR5_11": ["Was kommt als nächstes in der Zeichenfolge: 2, 4, 7, 14, 17, ?", "Operationen wechseln zwischen zwei verschiedenen Regeln in ungeraden und geraden Schritten.", ["34", "20", "31", "37"], "Das Muster wechselt: ×2, +3, ×2, +3, ×2. Also 17 × 2 = 34."],
    "TNR5_12": ["Was kommt als nächstes in der Zeichenfolge: 1, 5, 19, 65, 211, ?", "Drücken Sie jeden Term als Differenz zweier Exponentialfunktionen aus.", ["665", "660", "633", "670"], "Jeder Term ist 3ⁿ − 2ⁿ: 3−2=1, 9−4=5, 27−8=19, 81−16=65, 243−32=211, 729−64=665."],
    "TNR5_13": ["Was kommt als nächstes in der Zeichenfolge: 1, 4, 11, 29, 76, ?", "Jeder Begriff hängt von den beiden davor ab. Versuchen Sie es mit einer linearen Kombination.", ["199", "197", "200", "228"], "Die Regel lautet a(n) = 3×a(n−1) − a(n−2): 3×29−11=76, 3×76−29=199."],
    "TNR5_14": ["Was kommt als nächstes in der Zeichenfolge: 20, 22, 26, 34, 50, ?", "Die Unterschiede betragen 2, 4, 8, 16 – Zweierpotenzen.", ["82", "66", "80", "84"], "Die Differenzen sind Potenzen von 2: 2, 4, 8, 16. Die nächste Differenz ist 32, also 50 + 32 = 82."],
    "TNR5_15": ["Was kommt als nächstes in der Zeichenfolge: 1, 4, 10, 20, 35, ?", "Dies sind Tetraederzahlen – Summen aufeinanderfolgender Dreieckszahlen.", ["56", "50", "55", "60"], "Tetraederzahlen: n(n+1)(n+2)/6. Für n=6: 6×7×8/6 = 56."],
    "TNR5_16": ["Was kommt als nächstes in der Zeichenfolge: 1, 13, 37, 73, 121, ?", "Die Unterschiede betragen 12, 24, 36, 48 – Vielfache von 12.", ["181", "169", "175", "193"], "Das sind Sternzahlen: 6n(n−1)+1. Für n=6: 6×30+1 = 181."],
    "TNR5_17": ["Was kommt als nächstes in der Zeichenfolge: 1, 7, 19, 37, 61, ?", "Die Unterschiede betragen 6, 12, 18, 24 – Vielfache von 6.", ["91", "85", "90", "97"], "Dies sind zentrierte hexagonale Zahlen: 3n(n−1)+1. Für n=6: 3×30+1 = 91."],
    "TNR5_18": ["Was kommt als nächstes in der Zeichenfolge: 3, 8, 17, 32, 57, ?", "Versuchen Sie, jeden Term als Summe eines Quadrats und einer Potenz von 2 auszudrücken.", ["100", "96", "98", "105"], "Jeder Term ist n² + 2ⁿ: 1+2=3, 4+4=8, 9+8=17, 16+16=32, 25+32=57, 36+64=100."],
    "TNR5_19": ["Was kommt als nächstes in der Zeichenfolge: 1, 4, 8, 11, 22, ?", "Es wechseln sich zwei unterschiedliche Operationen ab. Der eine addiert, der andere multipliziert.", ["25", "44", "24", "26"], "Das Muster wechselt: +3, ×2, +3, ×2, +3. Also 22 + 3 = 25."],
    "TNR5_20": ["Was kommt als nächstes in der Zeichenfolge: 1, 1, 3, 5, 11, ?", "Jeder Begriff verwendet beide vorherigen Begriffe mit unterschiedlicher Gewichtung.", ["21", "16", "22", "19"], "Die Regel lautet a(n) = a(n−1) + 2×a(n−2): 5 + 2×3 = 11, 11 + 2×5 = 21."],
    "TLR1_01": ["Alle Ärzte sind Profis. Dr. Adams ist Arzt. Welche Schlussfolgerung können Sie ziehen?", "Wenn alle X Y sind und Z X ist, dann ist Z Y.", ["Dr. Adams ist professionell", "Dr. Adams ist kein Profi", "Manche Fachkräfte sind keine Ärzte", "Alle Fachkräfte sind Ärzte"], "Alle Ärzte sind Profis, und Dr. Adams ist ein Arzt, also ist Dr. Adams ein Profi. Dies ist ein direkter universeller positiver Syllogismus."],
    "TLR1_02": ["Alle Löwen sind Tiere. Simba ist ein Löwe. Welche Schlussfolgerung können Sie ziehen?", "Wenn jedes Mitglied der Gruppe X zur Gruppe Y gehört und Simba in X ist ...", ["Simba ist ein Tier", "Alle Tiere sind Löwen", "Simba ist kein Tier", "Manche Tiere sind keine Löwen"], "Alle Löwen sind Tiere, Simba ist ein Löwe, also ist Simba ein Tier."],
    "TLR1_03": ["Alle Orangen sind Früchte. Dieses Objekt ist eine Orange. Welche Schlussfolgerung können Sie ziehen?", "Wenn irgendeine Orange eine Frucht ist und dieser Gegenstand eine Orange ist ...", ["Dieses Objekt ist Obst", "Alle Früchte sind Orangen", "Dieses Objekt ist pflanzlich", "Bei diesem Artikel handelt es sich möglicherweise nicht um Obst"], "Alle Orangen sind Früchte, dieses Objekt ist eine Orange, also ist es eine Frucht."],
    "TLR1_04": ["Alle Autos sind Fahrzeuge. Ein BMW ist ein Auto. Welche Schlussfolgerung können Sie ziehen?", "Autos sind eine Untergruppe von Fahrzeugen. Wo passt BMW hinein?", ["Der BMW ist ein Fahrzeug", "Alle Fahrzeuge sind Autos", "Der BMW ist kein Fahrzeug", "Manche Fahrzeuge sind keine Autos"], "Alle Autos sind Fahrzeuge, BMW ist Auto, also ist BMW Fahrzeug."],
    "TLR1_05": ["Kein Vogel ist ein Insekt. Eine Amsel ist ein Vogel. Welche Schlussfolgerung können Sie ziehen?", "Wenn kein X Y ist und die Amsel X ist ...", ["Eine Amsel ist kein Insekt", "Die Amsel ist ein Insekt", "Einige Insekten sind Vögel", "Alle Amseln sind Insekten"], "Vögel sind keine Insekten, Amseln sind Vögel, also können Amseln keine Insekten sein."],
    "TLR1_06": ["Jedes Eis ist kalt. Der Würfel auf dem Tisch besteht aus Eis. Welche Schlussfolgerung können Sie ziehen?", "Wenn alles, was Eis ist, kalt ist und der Würfel Eis ist ...", ["Der Würfel ist kalt", "Der Würfel ist warm", "Nicht jedes Eis ist kalt", "Der Tisch ist kalt"], "Jedes Eis ist kalt, der Würfel ist Eis, also ist der Würfel kalt."],
    "TLR1_07": ["Alle Geigen sind Musikinstrumente. Eine Stradivari ist eine Geige. Welche Schlussfolgerung können Sie ziehen?", "Violinen gehören zur Vielzahl der Instrumente. Stradivari ist…", ["Stradivari ist ein Instrument", "Alle Instrumente sind Geigen", "Stradivari ist kein Instrument", "Einige Instrumente können nicht gespielt werden"], "Alle Geigen sind Instrumente, die Stradivari ist eine Geige, also ist die Stradivari ein Instrument."],
    "TLR1_08": ["Alle Rosen sind Pflanzen. Dieses Exemplar ist rosa. Welche Schlussfolgerung können Sie ziehen?", "Rosen sind eine Untergruppe der Pflanzen. Das Exemplar ist rosa, also…", ["Das Exemplar ist eine Pflanze", "Alle Pflanzen sind Rosen", "Das Exemplar ist keine Pflanze", "Rosen sind keine Pflanzen"], "Alle Rosen sind Pflanzen, dieses Exemplar ist eine Rose, also ist es eine Pflanze."],
    "TLR1_09": ["Alles Gold ist metallisch. Dieser Ring ist aus Gold gefertigt. Welche Schlussfolgerung können Sie ziehen?", "Gold ist immer metallisch. Der Ring ist aus Gold, also...", ["Der Ring ist metallisch", "Alle Metallkörper sind aus Gold", "Der Ring ist nicht aus Metall", "Gold ist manchmal nichtmetallisch"], "Alles Gold ist metallisch, der Ring ist aus Gold, also ist der Ring metallisch."],
    "TLR1_10": ["Alle Flüsse führen fließendes Wasser. Der Amazonas ist ein Fluss. Welche Schlussfolgerung können Sie ziehen?", "Wenn jeder Fluss fließendes Wasser hat und der Amazonas ein Fluss ist ...", ["Der Amazonas verfügt über fließendes Wasser", "Alles fließende Wasser ist Fluss", "Der Amazonas enthält kein Wasser", "Einige Flüsse sind trocken"], "Alle Flüsse enthalten fließendes Wasser, der Amazonas ist ein Fluss, also enthält er fließendes Wasser."],
    "TLR1_11": ["Alle Romane sind Bücher. Alle Bücher haben Seiten. Welche Schlussfolgerung können Sie ziehen?", "Verbinde die Beziehungen: Romane → Bücher → Seiten.", ["Alle Romane haben Seiten", "Alle Seiten sind nur auf Rumänisch", "Manche Bücher sind keine Romane", "Romane haben keine Seiten"], "Alle Romane sind Bücher, alle Bücher haben Seiten, also haben aufgrund der Transitivität alle Romane Seiten."],
    "TLR1_12": ["Alle Köche wissen, wie man kocht. Pierre ist Koch. Welche Schlussfolgerung können Sie ziehen?", "Wenn jeder Koch kochen kann und Pierre ein Koch ist ...", ["Pierre kann kochen", "Wer kochen kann, ist Koch", "Pierre kann nicht kochen", "Manche Köche wissen nicht, wie man kocht"], "Alle Köche können kochen, Pierre ist ein Koch, also weiß Pierre, wie man kocht."],
    "TLR1_13": ["Alle Adler sind Vögel. Alle Vögel haben Federn. Welche Schlussfolgerung können Sie ziehen?", "Verbinden Sie die Massen: Adler ⊂ Vögel ⊂ gefiederte Kreaturen.", ["Alle Adler haben Federn", "Alle fliegenden Lebewesen sind Adler", "Adler haben keine Federn", "Manche Vögel sind keine Adler"], "Alle Adler sind Vögel, alle Vögel haben Federn, also haben alle Adler Federn."],
    "TLR1_14": ["Alle Planeten kreisen um einen Stern. Saturn ist Planet. Welche Schlussfolgerung können Sie ziehen?", "Planeten umkreisen Sterne. Saturn ist ein Planet, also ...", ["Saturn umkreist einen Stern", "Alles, was einen Stern umkreist, ist ein Planet", "Saturn umkreist keinen Stern", "Der Stern umkreist Saturn"], "Alle Planeten umkreisen einen Stern, Saturn ist ein Planet, also umkreist Saturn einen Stern."],
    "TLR1_15": ["Alle Wale sind Säugetiere. Der Blauwal ist ein Wal. Welche Schlussfolgerung können Sie ziehen?", "Wale sind eine Untergruppe der Säugetiere. Der Blauwal ist ein Wal, also ...", ["Der Blauwal ist ein Säugetier", "Alle Säugetiere sind Wale", "Der Blauwal ist ein Fisch", "Einige Wale sind keine Säugetiere"], "Alle Wale sind Säugetiere, der Blauwal ist ein Wal, also ein Säugetier."],
    "TLR1_16": ["Kein Pflanzenfresser frisst Fleisch. Das Kaninchen ist ein Pflanzenfresser. Welche Schlussfolgerung können Sie ziehen?", "Wenn kein Pflanzenfresser Fleisch frisst und das Kaninchen ein Pflanzenfresser ist ...", ["Das Kaninchen frisst kein Fleisch", "Das Kaninchen frisst Fleisch", "Einige Pflanzenfresser fressen Fleisch", "Alle Fleischfresser sind Kaninchen"], "Pflanzenfresser fressen kein Fleisch, das Kaninchen ist ein Pflanzenfresser und frisst daher kein Fleisch."],
    "TLR1_17": ["Alle Welpen sind Hunde. Alle Hunde sind Caniden. Welche Schlussfolgerung können Sie ziehen?", "Kette: Welpen ⊂ Hunde ⊂ Caniden.", ["Alle Welpen sind Caniden", "Alle Caniden sind Welpen", "Welpen sind keine Hunde", "Manche Hunde sind keine Caniden"], "Alle Welpen sind Hunde, alle Hunde sind Caniden, also sind alle Welpen Caniden."],
    "TLR1_18": ["Alle Lehrer sind im Bildungsbereich tätig. Herr Brown ist Lehrer. Welche Schlussfolgerung können Sie ziehen?", "Wenn jeder Lehrer im Bildungswesen arbeitet und Herr Brown ein Lehrer ist ...", ["Herr Brown arbeitet im Bildungsbereich", "Jeder in der Bildung ist ein Lehrer", "Herr Brown arbeitet nicht im Bildungswesen", "Einige Lehrer arbeiten nicht im Bildungswesen"], "Alle Lehrer arbeiten im Bildungswesen, Herr Brown ist Lehrer, also arbeitet er im Bildungswesen."],
    "TLR1_19": ["Alle Diamanten sind Edelsteine. Alle Edelsteine ​​sind wertvoll. Welche Schlussfolgerung können Sie ziehen?", "Kette: Diamanten ⊂ Edelsteine ​​⊂ Wertsachen.", ["Alle Diamanten sind wertvoll", "Alle wertvollen Dinge sind Diamanten", "Diamanten sind nicht wertvoll", "Manche Edelsteine sind wertlos"], "Alle Diamanten sind Edelsteine, sie sind wertvoll, daher sind alle Diamanten wertvoll."],
    "TLR1_20": ["Alle Sommertage sind heiß. Heute ist ein Sommertag. Welche Schlussfolgerung können Sie ziehen?", "Wenn jeder Sommertag heiß ist und heute ein Sommertag ist ...", ["Heute ist heiß", "Alle warmen Tage sind Sommer", "Heute ist es kalt", "Sommertage sind nicht immer heiß"], "Alle Sommertage sind heiß, heute ist Sommertag, also ist es heute heiß."],
    "TLR2_01": ["Wenn es schneit, liegt die Temperatur unter dem Gefrierpunkt. Schnee. Welche Schlussfolgerung können Sie ziehen?", "Modus ponens: Wenn P→Q und P wahr ist, dann ist Q wahr.", ["Die Temperatur liegt unter dem Gefrierpunkt", "Die Temperatur liegt über dem Gefrierpunkt", "Es schneit nicht", "Es kann keine Schlussfolgerung gezogen werden"], "Modus ponens: P→Q (Schnee → unter dem Gefrierpunkt). P ist wahr, also ist Q wahr."],
    "TLR2_02": ["Wenn Sie regelmäßig lernen, verbessern sich Ihre Noten. Ihre Noten haben sich nicht verbessert. Welche Schlussfolgerung können Sie ziehen?", "Modus tollens: Wenn P→Q und Q falsch ist, dann ist P falsch.", ["Du hast nicht regelmäßig gelernt", "Sie haben regelmäßig gelernt", "Die Noten verbesserten sich", "Lernen hat keinen Einfluss auf die Noten"], "Modus tollens: P→Q (Lernen → bessere Noten). Q ist falsch, also ist P falsch."],
    "TLR2_03": ["Wenn das Telefon vollständig aufgeladen ist, hält es den ganzen Tag. Ihr Telefon ist vollständig aufgeladen. Welche Schlussfolgerung können Sie ziehen?", "Die Voraussetzung ist wahr – es gilt der Modus Ponens.", ["Das Telefon hält den ganzen Tag", "Das Telefon hält nicht den ganzen Tag", "Das Telefon wird nicht aufgeladen", "Es kann keine Schlussfolgerung gezogen werden"], "Modus ponens: P→Q (aufgeladen → den Tag halten). P ist wahr, also ist Q wahr."],
    "TLR2_04": ["Wenn der Wecker eingestellt ist, klingelt es um 7 Uhr morgens. Der Wecker hat um 7 Uhr nicht geklingelt. Welche Schlussfolgerung können Sie daraus ziehen?", "Die Konsequenz ist falsch – es gilt der Modus Tollens.", ["Der Alarm wurde nicht eingestellt", "Der Wecker wurde gestellt", "Um 7 Uhr klingelte der Wecker", "Der Alarm ist kaputt"], "Modus tollens: P→Q (hängen → klingeln). Q ist falsch, also ist P falsch."],
    "TLR2_05": ["Wenn Sie den richtigen Schlüssel haben, öffnet sich das Schloss. Sie haben den richtigen Schlüssel. Welche Schlussfolgerung können Sie ziehen?", "Die Voraussetzung ist erfüllt – es gilt der Modus Ponens.", ["Das Schloss öffnet sich", "Das Schloss öffnet sich nicht", "Sie haben nicht den richtigen Schlüssel", "Das Schloss klemmt"], "Modus ponens: P→Q (richtiger Schlüssel → Öffnen). P ist wahr, also ist Q wahr."],
    "TLR2_06": ["Wenn der Strom eingeschaltet ist, läuft der Kühlschrank. Der Kühlschrank funktioniert nicht. Welche Schlussfolgerung können Sie ziehen?", "Die Konsequenz ist falsch – es gilt der Modus Tollens.", ["Der Strom ist nicht eingeschaltet", "Der Strom ist eingeschaltet", "Der Kühlschrank funktioniert", "Es kann keine Schlussfolgerung gezogen werden"], "Modus tollens: P→Q (aktuell → laufend). Q ist falsch, also ist P falsch."],
    "TLR2_07": ["Wenn Sie die Pflanzen täglich gießen, bleiben sie grün. Benutze sie täglich. Welche Schlussfolgerung können Sie ziehen?", "Die Bedingung ist erfüllt – wie geht es weiter?", ["Ihre Pflanzen bleiben grün", "Pflanzen verdorren", "Benutze sie nicht", "Gießen hat keine Wirkung"], "Modus ponens: P→Q (tägliches Gießen → Grüns). P ist wahr, also ist Q wahr."],
    "TLR2_08": ["Wenn das Auto Kraftstoff hat, kann der Motor starten. Der Motor startet nicht. Welche Schlussfolgerung können Sie ziehen?", "Das Ergebnis ist nicht eingetreten – modus tollens anwenden.", ["Das Auto hat keinen Treibstoff", "Das Auto hat Treibstoff", "Der Motor sprang an", "Es kann keine Schlussfolgerung gezogen werden"], "Modus tollens: P→Q (Kraftstoff → Start). Q ist falsch, also ist P falsch."],
    "TLR2_09": ["Wenn Sie ein Ticket kaufen, können Sie in den Zug einsteigen. Du hast ein Ticket gekauft. Welche Schlussfolgerung können Sie ziehen?", "Sie haben die Bedingung erfüllt – was kommt als nächstes?", ["Sie können in den Zug einsteigen", "Du kannst nicht in den Zug einsteigen", "Du hast kein Ticket gekauft", "Der Zug fällt aus"], "Modus ponens: P→Q (Ticket → Anstiege). P ist wahr, also ist Q wahr."],
    "TLR2_10": ["Wenn Sie einen gültigen Reisepass besitzen, können Sie die Grenze passieren. Sie können die Grenze nicht überschreiten. Welche Schlussfolgerung können Sie ziehen?", "Wenn P→Q und Q falsch ist, was bedeutet das für P?", ["Sie haben keinen gültigen Reisepass", "Sie besitzen einen gültigen Reisepass", "Du hast die Grenze überschritten", "Kein Reisepass erforderlich"], "Modus tollens: P→Q (Pass → Pass). Q ist falsch, also ist P falsch."],
    "TLR2_11": ["Wenn ein Tier ein Pferd ist, hat es vier Beine. Dieses Tier hat vier Beine. Welche Schlussfolgerung können Sie ziehen?", "Die Wahrheit der Konsequenz beweist nicht die Antezedenz. Viele Tiere haben vier Beine.", ["Wir können nicht den Schluss ziehen, dass es sich um ein Pferd handelt", "Es ist definitiv ein Pferd", "Es hat zwei Beine", "Es ist kein Tier"], "Irrtum, die Konsequenz zu behaupten: P→Q und Q führen nicht zu P. Viele Tiere, die keine Pferde sind, haben vier Beine."],
    "TLR2_12": ["Wenn jemand Anwalt ist, hat er Jura studiert. Sam hat Jura studiert. Welche Schlussfolgerung können Sie ziehen?", "Nur weil Q wahr ist, folgt daraus nicht, dass P wahr ist.", ["Wir können nicht den Schluss ziehen, dass Sam Anwalt ist", "Sam ist definitiv Anwalt", "Sam hat kein Jurastudium studiert", "Alle, die Jura studiert haben, sind Juristen"], "Aussage der Konsequenz: Aus P→Q (Rechtsanwalt → Jurastudium) und Q folgt nicht, dass Sam Anwalt ist."],
    "TLR2_13": ["Wenn der Ofen eingeschaltet ist, heizt die Küche auf. Die Küche ist nicht warm. Welche Schlussfolgerung können Sie ziehen?", "Die Konsequenz ist falsch – Modus tollens.", ["Der Ofen ist nicht beleuchtet", "Der Ofen ist eingeschaltet", "Die Küche ist warm", "Es kann keine Schlussfolgerung gezogen werden"], "Modus tollens: P→Q (Ofen → warm). Q ist falsch, also ist P falsch."],
    "TLR2_14": ["Wenn Sie auf die Bremse treten, wird das Auto langsamer. Du trittst auf die Bremse. Welche Schlussfolgerung können Sie ziehen?", "Die Voraussetzung ist wahr – Modus Ponens.", ["Das Auto wird langsamer", "Das Auto beschleunigt", "Du hast nicht auf die Bremse getreten", "Es passiert nichts"], "Modus ponens: P→Q (bremsen → verlangsamen). P ist wahr, also ist Q wahr."],
    "TLR2_15": ["Wenn es schneit, ist der Himmel bewölkt. Der Himmel ist bewölkt. Welche Schlussfolgerung können Sie ziehen?", "Bewölkter Himmel kann auch ohne Schnee sein – ist die Aussage konsistent?", ["Wir können nicht darauf schließen, dass es schneit", "Natürlich schneit es", "Der Himmel ist klar", "Es schneit nie, wenn es bewölkt ist"], "Aussage der Konsequenz: P→Q und Q ergeben nicht P."],
    "TLR2_16": ["Wenn der Akku geladen ist, funktioniert die Taschenlampe. Die Taschenlampe funktioniert nicht. Welche Schlussfolgerung können Sie ziehen?", "Q ist falsch – was sagt das über P aus?", ["Der Akku ist nicht geladen", "Der Akku ist geladen", "Die Taschenlampe funktioniert", "Es kann keine Schlussfolgerung gezogen werden"], "Modus tollens: P→Q (geladen → funktionsfähig). Q ist falsch, also ist P falsch."],
    "TLR2_17": ["Wenn man dem Tee Zucker hinzufügt, wird der Tee süß. Sie geben Zucker in Ihren Tee. Welche Schlussfolgerung können Sie ziehen?", "Die Bedingung ist erfüllt – Modus Ponens.", ["Der Tee wird süß", "Der Tee bleibt bitter", "Du hast keinen Zucker hinzugefügt", "Zucker hat keine Wirkung"], "Modus ponens: P→Q (Zucker → süß). P ist wahr, also ist Q wahr."],
    "TLR2_18": ["Wenn der WLAN-Router eingeschaltet ist, können die Geräte eine Verbindung zum Internet herstellen. Die Geräte können keine Verbindung herstellen. Welche Schlussfolgerung können Sie ziehen?", "Q ist falsch – Modus tollens.", ["Der WLAN-Router ist nicht eingeschaltet", "Der WLAN-Router ist eingeschaltet", "Geräte können eine Verbindung herstellen", "Das Internet existiert nicht"], "Modus tollens: P→Q (ein → verbinden). Q ist falsch, also ist P falsch."],
    "TLR2_19": ["Wenn sich ein Student für den Kurs anmeldet, erhält er den Lehrplan. Emma hat sich für den Kurs angemeldet. Welche Schlussfolgerung können Sie ziehen?", "Emma hat die Bedingung erfüllt – was kommt als nächstes?", ["Emma erhält den Lehrplan", "Emma versteht den Lehrplan nicht", "Emma hat sich nicht angemeldet", "Der Kurs hat keinen Zeitplan"], "Modus ponens: P→Q (geschrieben → Programm). P gilt für Emma, ​​​​also ist Q wahr."],
    "TLR2_20": ["Wenn es Sonntag ist, ist der Laden geschlossen. Es ist nicht Sonntag. Welche Schlussfolgerung können Sie ziehen?", "Der Antezedens ist falsch – er sagt Ihnen nicht, ob Q wahr ist (Negation des Antezedens).", ["Wir können nicht feststellen, ob der Laden geöffnet oder geschlossen ist", "Der Laden ist definitiv geöffnet", "Der Laden ist definitiv geschlossen", "Es muss Samstag sein"], "Das Antezedens zu leugnen ist ein Fehler: Aus P→Q und falschem P folgt nichts Sicheres über Q."],
    "TLR3_01": ["Anna ist größer als Dana. Dana ist größer als Ben. Ben ist größer als Carl. Wer ist der Kleinste?", "Write the chain of inequalities and find the \"base\".", ["Carl", "Ben", "Dana", "Anna"], "Anna > Dana > Ben > Carl. Carl ist klein, also der Kürzeste."],
    "TLR3_02": ["Felix ist leichter als George. Harry ist schwerer als George. Ivan ist leichter als Felix. Wer ist am härtesten?", "Reihenfolge: Harry > George > Felix > Ivan.", ["Harry", "Georg", "Felix", "Iwan"], "Harry > George > Felix > Ivan. Am schwersten fällt es Harry."],
    "TLR3_03": ["Mia ist jünger als Nina. Oscar ist älter als Nina. Pam ist jünger als Mia. Wer ist der Älteste?", "Oscar > Nina > Mia > Pam. Wer ist oben?", ["Oskar", "Nina", "Mia", "Pam"], "Oscar > Nina > Mia > Pam. Der Älteste ist Oscar."],
    "TLR3_04": ["In einem Rennen kommt Raj hinter Sam ins Ziel. Tina war vor Sam fertig. Uma ist nach Raj fertig. Wer ist zuerst fertig?", "Zuerst in der Reihenfolge der Ankunft = besserer Sitzplatz. Kette: Tina → Sam → Raj → Uma.", ["Tina", "Sam", "Raj", "Uma"], "Reihenfolge: Tina, Sam, Raj, Uma. Die erste ist Tina."],
    "TLR3_05": ["Victor verdient weniger als Wendy. Wendy verdient weniger als Xavier. Yara verdient mehr als Xavier. Wer gewinnt am meisten?", "Kette: Victor < Wendy < Xavier < Yara.", ["Yara", "Xavier", "Wendy", "Viktor"], "Yara > Xavier > Wendy > Victor. Yara gewinnt am meisten."],
    "TLR3_06": ["Eve hat eine höhere Punktzahl als Frank. Grace hat eine niedrigere Punktzahl als Frank. Dave hat eine höhere Punktzahl als Eve. Wer hat die niedrigste Punktzahl?", "Dave > Eve > Frank > Grace. Wer ist unten?", ["Gnade", "Frank", "Eva", "Dave"], "Dave > Eve > Frank > Grace. Grace hat die niedrigste Punktzahl."],
    "TLR3_07": ["Lily schwimmt schneller als Max. Olivia schwimmt schneller als Lily. Noah schwimmt langsamer als Max. Wer schwimmt am langsamsten?", "Nach Geschwindigkeit: Olivia > Lily > Max > Noah.", ["Noah", "Max", "Lilie", "Olivia"], "Olivia > Lily > Max > Noah. Der Langsamste ist Noah."],
    "TLR3_08": ["Quinn ist kleiner als Ruth. Steve ist größer als Tom. Tom ist größer als Ruth. Wer ist der Größte?", "Kette: Steve > Tom > Ruth > Quinn.", ["Steve", "Tom", "Ruth", "Quinn"], "Steve > Tom > Ruth > Quinn. Der Größte ist Steve."],
    "TLR3_09": ["Amy wiegt weniger als Brian. Clara wiegt mehr als Dan. Dan wiegt mehr als Brian. Wer ist am einfachsten?", "Clara > Dan > Brian > Amy.", ["Amy", "Brian", "Dan", "Clara"], "Clara > Dan > Brian > Amy. Am einfachsten ist Amy."],
    "TLR3_10": ["Jake rennt langsamer als Kim. Leo rennt schneller als Mona. Mona rennt schneller als Kim. Wer ist der Zweitschnellste?", "Leo > Mona > Kim > Jake. Zweite?", ["Mona", "Kim", "Löwe", "Jack"], "Leo > Mona > Kim > Jake. Zweite in Sachen Geschwindigkeit ist Mona."],
    "TLR3_11": ["In einer Gruppe von 20 Schülern spielen 12 Tennis und 10 Fußball. Jeder betreibt mindestens eine Sportart. Wie viele machen beides?", "Beide = A + B − insgesamt (wenn jeder mindestens einen ergibt).", ["2", "4", "8", "10"], "12 + 10 − 20 = 2. Zwei Schüler betreiben beide Sportarten."],
    "TLR3_12": ["In einer Gruppe von 25 Personen mögen 18 Kaffee und 13 Tee. Jeder mag mindestens einen. Wie viele Leute mögen beides?", "Beides = Kaffee + Tee − insgesamt.", ["6", "5", "7", "8"], "18 + 13 − 25 = 6. Sechs Leute mögen beides."],
    "TLR3_13": ["In einem Unternehmen mit 35 Mitarbeitern sprechen 20 Französisch und 22 Deutsch. Jeder spricht mindestens eins. Wie viele sprechen beide?", "Beide = Französisch + Deutsch − insgesamt.", ["7", "5", "8", "13"], "20 + 22 − 35 = 7. Sieben Mitarbeiter sprechen beides."],
    "TLR3_14": ["Von einer Gruppe von 40 Touristen besuchten 28 das Museum und 18 den Park. Jeder hat mindestens einen Ort besucht. Wie viele haben beide besucht?", "Beides = Museum + Park − gesamt.", ["6", "10", "8", "4"], "28 + 18 − 40 = 6. Sechs Touristen besuchten beide."],
    "TLR3_15": ["In einer Gruppe von 30 Lesern lasen 16 Belletristik und 20 Sachbücher. Jeder liest mindestens einen Typ. Wie viele lesen beides?", "Beides = Belletristik + Sachbuch − insgesamt.", ["6", "4", "10", "14"], "16 + 20 − 30 = 6. Sechs Leser lesen beide."],
    "TLR3_16": ["In einer Reihe ist Alice die 3. von links und die 5. von rechts. Wie viele Personen stehen in der Schlange?", "Gesamt = linke Position + rechte Position − 1.", ["7", "8", "6", "9"], "3 + 5 − 1 = 7. Es gibt 7 Personen."],
    "TLR3_17": ["In Folge ist Bob 7. von links und 4. von rechts. Wie viele Leute gibt es?", "Gesamt = links + rechts − 1.", ["10", "11", "9", "12"], "7 + 4 − 1 = 10. Es gibt 10 Personen."],
    "TLR3_18": ["In Folge ist Carol 5. von vorne und 9. von hinten. Wie viele Personen stehen in der Schlange?", "Gesamt = vorne + hinten − 1.", ["13", "14", "12", "15"], "5 + 9 − 1 = 13. Es gibt 13 Personen."],
    "TLR3_19": ["David ist in Folge 9. vorne und 3. hinten. Wie viele Leute gibt es?", "Gesamt = vorne + hinten − 1.", ["11", "12", "10", "13"], "9 + 3 − 1 = 11. Es gibt 11 Personen."],
    "TLR3_20": ["In Folge ist Emily die 6. von links und die 6. von rechts. Wie viele Leute gibt es?", "Gesamt = links + rechts − 1.", ["11", "12", "10", "13"], "6 + 6 − 1 = 11. Es gibt 11 Personen."],
    "TLR4_01": ["Fünf Personen werden nach Gewicht verglichen. E ist härter als A, A als B, C als D, D als B, A als C. Rangfolge vom schwersten zum leichtesten.", "Erstellen Sie die Kette: E > A > C > D > B.", ["E, A, C, D, B", "E, A, D, C, B", "A, E, C, D, B", "E, C, A, D, B"], "E > A > C > D > B. Das Schwierigste ist E, das Leichteste B."],
    "TLR4_02": ["Fünf Läufer beenden ein Rennen. Sam kommt vor Priya ins Ziel, Priya vor Quinn, Quinn vor Tara, Tara vor Rosa. Wer landet auf dem 3. Platz?", "Reihenfolge der Ankunft: Sam → Priya → Quinn → Tara → Rosa.", ["Quinn", "Priya", "Land", "Sam"], "Sam, Priya, Quinn, Tara, Rosa. Der Dritte ist Quinn."],
    "TLR4_03": ["Fünf Schüler haben unterschiedliche Noten. Jack > Fred > Gina > Iris > Hank. Wer hat die zweitniedrigste Punktzahl (vorletzter Platz)?", "Nummer von unten nach oben: Hank, Iris…", ["Iris", "Gina", "Hank", "Fred"], "Zweite von unten (nach Hank) ist Iris."],
    "TLR4_04": ["Sechs Athleten nach Geschwindigkeit: Elena > Diana > Ava > Bella > Chloe > Fiona. Sortieren Sie vom Schnellsten zum Langsamsten.", "Bauen Sie Schritt für Schritt auf.", ["Elena, Diana, Ava, Bella, Chloe, Fiona", "Diana, Elena, Ava, Bella, Chloe, Fiona", "Elena, Ava, Diana, Bella, Chloe, Fiona", "Elena, Diana, Bella, Ava, Chloe, Fiona"], "Elena > Diana > Ava > Bella > Chloe > Fiona."],
    "TLR4_05": ["Fünf Städte nach Einwohnerzahl: Penny > Liam > Mason > Oliver > Noah. Sortieren Sie von der höchsten bis zur geringsten Bevölkerungszahl.", "Penny > Liam > Mason > Oliver > Noah.", ["Penny, Liam, Mason, Oliver, Noah", "Liam, Penny, Mason, Oliver, Noah", "Penny, Mason, Liam, Oliver, Noah", "Penny, Liam, Oliver, Mason, Noah"], "Penny > Liam > Mason > Oliver > Noah."],
    "TLR4_06": ["In einem Unternehmen mit 60 Mitarbeitern nutzen 38 Windows und 30 Mac. Jeder nutzt mindestens ein System. Wie viele nutzen beides?", "Beide = Windows + Mac − insgesamt.", ["8", "10", "12", "6"], "38 + 30 − 60 = 8."],
    "TLR4_07": ["In einer Schule mit 80 Schülern studieren 55 Mathematik und 42 Naturwissenschaften. Jeder studiert mindestens ein Fach. Wie viele studieren beides?", "Beides = Mathematik + Naturwissenschaften − Gesamtsumme.", ["17", "15", "20", "23"], "55 + 42 − 80 = 17."],
    "TLR4_08": ["In einem Verein mit 75 Mitgliedern spielen 50 Schach und 40 Dame. Jeder spielt mindestens ein Spiel. Wie viele spielen beides?", "Beide = Dame + Dame − insgesamt.", ["15", "10", "20", "25"], "50 + 40 − 75 = 15."],
    "TLR4_09": ["In einer Umfrage unter 90 Personen bevorzugen 60 Schokolade und 52 Vanille. Jeder mag mindestens einen Geschmack. Wie viele Leute mögen beides?", "Beides = Schokolade + Vanille − insgesamt.", ["22", "18", "30", "12"], "60 + 52 − 90 = 22."],
    "TLR4_10": ["In einer Gruppe von 100 Wählern unterstützen 72 Vorschlag A und 65 Vorschlag B. Jeder unterstützt mindestens einen. Wie viele unterstützen beides?", "Beide = A + B − insgesamt.", ["37", "35", "40", "28"], "72 + 65 − 100 = 37."],
    "TLR4_11": ["In einer Umfrage haben 50 Personen: 30 ein Auto, 25 ein Fahrrad, 10 beides. Wie viele haben keine?", "Mindestens eins = Auto + Fahrrad − beides. Keine = insgesamt − mindestens eine.", ["5", "10", "15", "0"], "30 + 25 − 10 = 45 haben mindestens eine. 50 − 45 = 5 haben keine."],
    "TLR4_12": ["In einer Klasse mit 45 Schülern bestanden 28 die Prüfungen in Mathematik, 20 in Naturwissenschaften und 8 in beidem. Wie viele haben genau ein Fach bestanden?", "Nur eins = (nur Mathematik) + (nur Naturwissenschaften).", ["32", "40", "28", "20"], "Nur Mathematik: 28−8=20. Nur Wissenschaft: 20−8=12. Insgesamt 32."],
    "TLR4_13": ["60 Personen: 40 spielen Gitarre, 30 spielen Klavier, jeder spielt mindestens ein Instrument. Wie viele singen genau eins?", "Beide = Gitarre + Klavier − 60. Genau eins = 60 − beide.", ["50", "60", "40", "30"], "Beide = 10. Genau einer = 50."],
    "TLR4_14": ["55 Studenten: 32 im Kunstkreis, 28 im Musikbereich, 12 in beiden. Wie viele sind in keinem Kreis?", "Mindestens einer = 32+28−12. Keine = 55 − dies.", ["7", "5", "10", "3"], "48 haben mindestens einen Kreis. 55−48=7."],
    "TLR4_15": ["70 Personen: 45 lesen Zeitungen, 38 Zeitschriften, 20 beides. Wie viel liest ein Mann genau?", "Genau eins = (nur Zeitung) + (nur Zeitschrift).", ["43", "63", "50", "33"], "25 + 18 = 43."],
    "TLR4_16": ["Wenn es kalt ist, trägt Tom eine Jacke. Wenn er eine Jacke trägt, nehmen Sie einen Regenschirm mit. Es ist kalt. Was nimmt Tom?", "Kette: Kälte → Jacke → Regenschirm. Modus ponens zweimal.", ["Ein Regenschirm", "Ein Hut", "Nichts", "Nur die Jacke"], "Es ist kalt → Jacke → Regenschirm. Nehmen Sie also einen Regenschirm mit."],
    "TLR4_17": ["Wenn Alice lernt, befördert sie. Wenn er besteht, macht er seinen Abschluss. Wenn er seinen Abschluss macht, bekommt er ein Jobangebot. Alice lernt. Was ist das Endergebnis?", "Kette: Lernen → Förderung → Abschluss → Angebot.", ["Alice erhält ein Jobangebot", "Alice besteht nur die Prüfung", "Alice macht gerade ihren Abschluss", "Es kann keine Schlussfolgerung gezogen werden"], "Alice durchläuft die gesamte Kette bis zum Stellenangebot."],
    "TLR4_18": ["Bei einem Stromausfall schaltet sich der Computer ab. Wenn es stoppt, gehen nicht gespeicherte Arbeiten verloren. Die Arbeit ging nicht verloren. Welche Schlussfolgerung ziehen Sie?", "Modus tollens in Kette.", ["Die Strömung fiel nicht", "Der Strom ging zurück", "Der Computer blieb stehen", "Die Arbeit ist verloren"], "Die Arbeit ist nicht verloren gegangen → Der Computer wurde nicht heruntergefahren → Der Strom ist nicht ausgefallen."],
    "TLR4_19": ["Bei Regen wird das Spiel abgesagt. Im Falle einer Absage erfolgt die Rückgabe der Tickets. Die Tickets wurden nicht zurückgegeben. Welche Schlussfolgerung?", "Nicht zurückgegeben → das Spiel nicht abgesagt → es hat nicht geregnet.", ["Es hat nicht geregnet", "Es hat geregnet", "Das Spiel wurde abgesagt", "Die Tickets wurden zurückgegeben"], "Doppelter Modus Tolles: Es regnet nicht."],
    "TLR4_20": ["Wenn Sie zu viel Zucker essen, nehmen Sie zu. Wer zunimmt, braucht Bewegung. Wenn Sie es brauchen, gehen Sie ins Fitnessstudio. Sie haben sich nicht für das Fitnessstudio angemeldet. Welche Schlussfolgerung?", "Modus tollens in Kette.", ["Du hast nicht zu viel Zucker gegessen", "Du hast zu viel Zucker gegessen", "Sie haben zugenommen", "Du hast dich für das Fitnessstudio angemeldet"], "Kein Fitnessstudio → kein zusätzlicher Bedarf → kein Mast → kein überschüssiger Zucker."],
    "TLR5_01": ["Drei Personen: A, B und C. Genau eine sagt die Wahrheit. A sagt: „B und C lügen beide.“ B sagt: „A lügt.“ C sagt: „A sagt die Wahrheit.“ Wer sagt die Wahrheit?", "Nimm nacheinander an, nur diese Person sage die Wahrheit — wo gibt es keinen Widerspruch?", ["B", "A", "C", "Keine"], "Wenn B die Wahrheit sagt: A lügt, also stimmt es nicht, dass B und C beide lügen — B ist ehrlich ✓. C lügt, also sagt A nicht die Wahrheit ✓. Nur B passt."],
    "TLR5_02": ["Drei Personen: D, E und F. Genau eine sagt die Wahrheit. D sagt: „E lügt.“ E sagt: „F lügt.“ F sagt: „D und E lügen beide.“ Wer sagt die Wahrheit?", "Prüfe jede Person als einzige Wahrheitssagerin.", ["E", "D", "F", "Keine"], "Wenn E die Wahrheit sagt: F lügt ✓. D sagt „E lügt“ — das ist falsch, also lügt D ✓. F lügt, wenn er behauptet, D und E lügen beide — passt, weil E ehrlich ist. Nur E ist konsistent."],
    "TLR5_03": ["G, H, I – Verdächtige. Nur ein Schuldiger. Der Schuldige lügt immer; Die Unschuldigen sagen die Wahrheit. G: „Er ist schuldig.“ H: „Ich bin nicht schuldig.“ Ich: „G ist schuldig“. Wer ist schuld?", "Ratet mal, wer der Reihe nach schuldig ist.", ["G", "H", "ich", "Es kann nicht bestimmt werden"], "Wenn G schuldig ist: G lügt → H unschuldig ✓; H und ich sagen die Wahrheit ✓. Der Rest führt zu Widersprüchen."],
    "TLR5_04": ["J, K, L. Genau einer sagt die Wahrheit. J: „Ich sage die Wahrheit.“ K: «J sagt die Wahrheit». L: „Ich lüge.“ Wer sagt die Wahrheit?", "Wenn J ehrlich wäre, wäre K auch ehrlich – unmöglich.", ["L", "J", "K", "Keine"], "L ehrlich → J Lügner → K Lügner ✓. Nur L funktioniert."],
    "TLR5_05": ["M, N, O. Genau einer sagt die Wahrheit. M: „N und O sagen beide die Wahrheit.“ N: „Ich lüge“. O: „Es macht mir nichts aus“. Wer sagt die Wahrheit?", "Wenn M ehrlich wäre, wären N und O beide ehrlich – widerspricht „genau eins“.", ["N", "m", "oh", "Keine"], "N ehrlich → M Lügner; Die Aussage von M ist falsch → nicht beide N,O ehrlich → O lügt ✓."],
    "TLR5_06": ["In drei Tagen ist Mittwoch. Welcher Tag ist heute?", "Zählen Sie ab Mittwoch drei Tage herunter.", ["Sonntag", "Montag", "Samstag", "Dienstag"], "Mittwoch −3 Tage = Sonntag."],
    "TLR5_07": ["Gestern war Freitag. Welcher Tag wird übermorgen sein?", "Finden Sie es heute heraus, dann +2 Tage.", ["Montag", "Sonntag", "Dienstag", "Samstag"], "Gestern Freitag → heute Samstag → übermorgen Montag."],
    "TLR5_08": ["Vor zwei Tagen war Montag. Welcher Tag wird in drei Tagen sein?", "Ermitteln Sie „heute“ von „vor zwei Tagen“, dann +3.", ["Samstag", "Freitag", "Sonntag", "Donnerstag"], "Vor zwei Tagen = Montag → heute = Mittwoch → in drei Tagen = Samstag."],
    "TLR5_09": ["Vorgestern war Donnerstag. Welcher Tag wird morgen sein?", "Vorgestern = vor zwei Tagen.", ["Sonntag", "Samstag", "Montag", "Freitag"], "Vorgestern Donnerstag → gestern Freitag → heute Samstag → morgen Sonntag."],
    "TLR5_10": ["In vier Tagen ist Dienstag. welcher Tag war gestern", "Heute = Dienstag − 4 Tage; gestern = heute − 1.", ["Donnerstag", "Freitag", "Mittwoch", "Samstag"], "Heute = Freitag, gestern = Donnerstag."],
    "TLR5_11": ["Sechs Schüler nach Klassenstufen: Fay > Diana > Abby > Brian > Carl > Elena. Wer ist der dritthöchste (Dritthöchste)?", "Top-Nummer: 1 Fay, 2 Diana, 3…", ["Abby", "Diana", "Brian", "Faye"], "Die Dritte ist Abby."],
    "TLR5_12": ["Fünf Gläser: 5>1>2>4>3 nach Gewicht. Welches ist in der Mitte (3. Platz)?", "Komplette Kette 5>1>2>4>3.", ["Glas 2", "Glas 1", "Glas 4", "Glas 3"], "An dritter Stelle steht Glas 2."],
    "TLR5_13": ["Sieben Personen nach Alter: T>U>V>W>X>Y>Z. Wer ist Vierter?", "Nummernposition 4 in der Kette.", ["w", "V", "X", "u"], "Der vierte ist W."],
    "TLR5_14": ["Fünf Städte: E>A>B>D>C nach Bevölkerung. Welches ist am dünnsten besiedelt?", "C steht am Ende der Kette.", ["Stadt C", "Stadt D", "Stadt B", "Stadt A"], "Der kleinste ist C."],
    "TLR5_15": ["Sechs Karten nach Seiten: T>P>Q>U>R>S. Welches hat die zweitwenigsten (vorletzten) Seiten?", "Unten: S minimal, dann R.", ["Buch R", "Buch S", "Das U-Buch", "Das Q-Buch"], "Zweiter von unten ist R."],
    "TLR5_16": ["Drei Kisten: „Äpfel“, „Orangen“, „Mischung“. Alle Etiketten sind falsch. Nehmen Sie einen Apfel aus der Box «Mischung». Was ist eigentlich in der Schachtel mit der Aufschrift „Äpfel“?", "„Mischung“ ist falsch – die Box ist homogen; Du hast einen Apfel herausgenommen → da sind die Äpfel.", ["Orangen", "Äpfel", "Mischung", "Es kann nicht bestimmt werden"], "Die Box „Mix“ enthält nur Äpfel. „Orange“ hat keine Orangen → Mischung. „Apple“ hat Orangen."],
    "TLR5_17": ["Alice, Bob und Carol arbeiten an verschiedenen Tagen: Montag, Dienstag, Mittwoch. Alice arbeitet montags nicht. Bob arbeitet dienstags und mittwochs nicht. Carol arbeitet mittwochs nicht. An welchem ​​Tag arbeitet Carol?", "Es beginnt mit Bob – er hat den einzig möglichen Tag.", ["Dienstag", "Montag", "Mittwoch", "Es kann nicht bestimmt werden"], "Bob nur montags → Alice dienstags oder mittwochs → Carol nicht mittwochs → Carol dienstags."],
    "TLR5_18": ["Wenn P wahr ist, ist Q wahr. Wenn Q wahr ist, ist R falsch. Wenn R falsch ist, ist S wahr. P ist wahr. Ist es wahr oder falsch?", "Gehen Sie durch die Kette P→Q→¬R→S.", ["Es ist wahr", "Es ist eine Fälschung", "S ist unbekannt", "S hängt von R ab"], "P → Q → R falsch → S wahr."],
    "TLR5_19": ["Fünf Freunde: Alex > Drew > Blake > Casey > Ellie nach Alter. Wer ist in der Mitte (drittjährig)?", "Der dritte von fünf.", ["Blake", "Drew", "Casey", "Alex"], "Der Dritte ist Blake."],
    "TLR5_20": ["In der Rangfolge V,W,X,Y,Z: V vor W; X unmittelbar nach Y; Z auf Platz 3; W auf Platz 5; Y vor Z. An welcher Stelle steht V?", "Z=3, W=5; Y vor Z; X nach Y.", ["4. Platz", "1. Platz", "2. Platz", "3. Platz"], "Y=1, X=2, Z=3, V=4, W=5."],
    "TSR1_01": ["Wie viele Seiten hat ein Fünfeck?", "Das Präfix „penta-“ bezieht sich auf eine bestimmte Zahl.", ["5", "4", "6", "7"], "„Pentagon“ kommt aus dem Griechischen und bedeutet fünf. Ein Fünfeck hat genau 5 Seiten."],
    "TSR1_02": ["Wie viele Seiten hat ein Sechseck?", "Das Präfix „hexa-“ gibt eine Zahl an – denken Sie an eine Hexadezimalzahl.", ["6", "5", "8", "7"], "„Hexagon“ kommt aus dem Griechischen und bedeutet sechs. Ein Sechseck hat 6 Seiten."],
    "TSR1_03": ["Wie viele Seiten hat ein Achteck?", "Denken Sie an den Oktopus – wie viele Arme hat er?", ["8", "6", "10", "7"], "Das Präfix „octa-“ bedeutet acht, wie in Oktopus. Ein Achteck hat 8 Seiten."],
    "TSR1_04": ["Wie viele Winkel hat ein Dreieck?", "Das Präfix «tri-» gibt Ihnen direkt die Antwort.", ["3", "4", "2", "1"], "Ein Dreieck hat drei Winkel – einen an jedem Scheitelpunkt, an dem sich zwei Seiten treffen."],
    "TSR1_05": ["Wie viele Winkel hat ein Fünfeck?", "Jede Seite trifft in einem Winkel auf die nächste. Zählen Sie die Seiten.", ["5", "4", "6", "3"], "Jedes Polygon hat so viele Winkel wie Seiten. Ein Fünfeck hat 5 Seiten und 5 Winkel."],
    "TSR1_06": ["Wie viele Flächen hat ein rechteckiger Kasten (rechteckiges Prisma)?", "Denken Sie nach oben, unten, vorne, hinten, links und rechts.", ["6", "4", "8", "5"], "Ein rechteckiges Prisma hat 6 Flächen: oben, unten, vorne, hinten, links, rechts."],
    "TSR1_07": ["Wie viele Eckpunkte (Ecken) hat ein Dreieck?", "Ein Scheitelpunkt ist die Stelle, an der sich zwei Seiten treffen. Zähle die Ecken.", ["3", "4", "2", "6"], "Ein Dreieck hat drei Eckpunkte – einen an jeder Ecke."],
    "TSR1_08": ["Welche 2D-Form hat genau 3 Seiten und 3 Winkel?", "Es ist eines der einfachsten Polygone.", ["Dreieck", "Quadratisch", "Pentagon", "Kreis"], "Ein Dreieck ist ein Polygon mit 3 Seiten und 3 Winkeln."],
    "TSR1_09": ["Wenn Sie ein Blatt Papier in der Mitte falten, wie viele Papierschichten haben Sie?", "Vor dem Falten haben Sie 1 Schicht. Verdoppeln Sie die Zahl.", ["2", "1", "3", "4"], "Jede Falte in der Mitte verdoppelt die Lagen. Ausgehend von 1 ergibt eine Falte 2 Schichten."],
    "TSR1_10": ["Welche Form hat jede Seite eines Standardwürfels?", "Alle Flächen des Würfels sind gleich. Welche regelmäßige Form hat 4 gleiche Seiten und 4 rechte Winkel?", ["Quadratisch", "Rechteck", "Dreieck", "Kreis"], "Der Würfel hat 6 Seiten und jede ist ein Quadrat."],
    "TSR1_11": ["Welcher 3D-Körper sieht gleich aus, egal wie man ihn in der Mitte durchschneidet?", "Es hat keine Kanten, keine Spitzen, es ist perfekt rund.", ["Kugel", "Zylinder", "Con", "Würfel"], "Die Kugel ist vollkommen symmetrisch. Jeder Schnitt durch die Mitte ergibt einen identischen Kreis."],
    "TSR1_12": ["Wie viele gerade Seiten hat ein Kreis?", "Der Kreis ist überall gekrümmt. Gibt es gerade Seiten?", ["0", "1", "2", "Unendlich"], "Der Kreis hat keine geraden Seiten – es ist eine kontinuierliche Kurve ohne Ecken oder gerade Segmente."],
    "TSR1_13": ["Wie viele Seiten hat ein Dreieck?", "Der Name sagt: „tri“ bedeutet drei.", ["3", "2", "4", "5"], "Ein Dreieck ist ein Polygon mit genau 3 Seiten."],
    "TSR1_14": ["Wie viele Seiten hat ein Quadrat?", "Denken Sie an ein Fenster oder ein Schachbrett.", ["4", "3", "5", "6"], "Ein Quadrat hat 4 gleiche Seiten und 4 rechte Winkel."],
    "TSR1_15": ["Wie viele Eckpunkte (Ecken) hat ein Quadrat?", "Zählen Sie die Punkte, an denen sich zwei Seiten treffen.", ["4", "3", "5", "6"], "Das Quadrat hat 4 Eckpunkte – einen an jeder Ecke."],
    "TSR1_16": ["Wie viele Eckpunkte hat ein Sechseck?", "Ein Polygon hat immer so viele Eckpunkte wie Seiten.", ["6", "5", "8", "4"], "Das Sechseck hat 6 Seiten, also 6 Eckpunkte."],
    "TSR1_17": ["Wie viele Schichten erhält man, wenn man ein Blatt zweimal in der Mitte faltet?", "Jede Faltung verdoppelt die aktuelle Anzahl der Schichten.", ["4", "2", "3", "8"], "Erste Falte: 1 → 2 Lagen. Zweitens: 2 → 4 Schichten."],
    "TSR1_18": ["Welche Form hat 4 Seiten, alle Winkel 90° und gegenüberliegende Seiten parallel?", "Es ist die gebräuchlichste Form für Türen, Paravents und Bücher.", ["Rechteck", "Trapez", "Raute", "Parallelogramm"], "Das Rechteck hat 4 Seiten, parallele Gegensätze, alle Innenwinkel 90°."],
    "TSR1_19": ["Wie viele Ecken hat ein Rechteck?", "Bei einer Ecke treffen zwei Seiten schräg aufeinander.", ["4", "2", "3", "5"], "Das Rechteck hat 4 Ecken (Eckpunkte), jeweils eine im rechten Winkel."],
    "TSR1_20": ["Bei welcher 2D-Form haben alle Punkte auf der Kontur den gleichen Abstand vom Mittelpunkt?", "Denken Sie an eine Münze von oben oder an eine Pizza.", ["Kreis", "Ellipse", "Quadratisch", "Oval"], "Ein Kreis ist die Menge von Punkten mit gleichem Abstand vom Mittelpunkt. Dieser konstante Abstand ist der Radius."],
    "TSR2_01": ["Wie viele Seiten hat ein rechteckiges Prisma (Kasten)?", "Zählen Sie die oberen und unteren Flächenkanten sowie die sie verbindenden vertikalen Kanten.", ["12", "8", "10", "6"], "Rechteckiges Prisma: 4 obere Kanten + 4 untere + 4 vertikale = 12 Kanten."],
    "TSR2_02": ["Wie viele Eckpunkte hat ein rechteckiges Prisma?", "Zählen Sie die oberen und unteren Flächenecken getrennt.", ["8", "6", "10", "12"], "4 stitches up + 4 stitches down = 8 stitches."],
    "TSR2_03": ["Wie viele Flächen hat ein fünfeckiges Prisma?", "Ein Prisma mit n-seitiger Basis hat n rechteckige Seitenflächen plus 2 Basen.", ["7", "5", "10", "6"], "2 fünfeckige Basen + 5 seitliche rechteckige Flächen = 7 Flächen."],
    "TSR2_04": ["Wie viele Kanten hat ein dreieckiges Prisma?", "Zählen Sie die Kanten jeder dreieckigen Basis und dann die Kanten, die sie verbinden.", ["9", "6", "8", "12"], "3 Kanten nach oben + 3 nach unten + 3 vertikal = 9 Kanten."],
    "TSR2_05": ["Wie viele Eckpunkte hat ein dreieckiges Prisma?", "Jede dreieckige Basis bringt ihre eigenen Eckpunkte mit.", ["6", "5", "8", "9"], "3 Spikes auf jeder Basis: 3 + 3 = 6 Spikes."],
    "TSR2_06": ["Wenn 4 identische Würfel in einer geraden Linie liegen und jeder eine gemeinsame Fläche mit dem nächsten hat, wie viele Flächen sind dann insgesamt sichtbar (einschließlich der Unterseite)?", "Es beginnt mit 4×6 Flächen und subtrahiert dann die verborgenen Flächen bei jeder Verbindung.", ["18", "20", "16", "24"], "4 Würfel: 24 Flächen. 3 Verbindungen × 2 verdeckte Flächen = 6. 24 − 6 = 18 sichtbar."],
    "TSR2_07": ["Wie viele Flächen hat ein sechseckiges Prisma?", "Das N-Eck-Basisprisma hat n + 2 Flächen.", ["8", "6", "12", "10"], "2 sechseckige Basen + 6 rechteckige Flächen = 8 Flächen."],
    "TSR2_08": ["Wie viele Kanten hat ein fünfeckiges Prisma?", "Für ein Prisma mit n-seitiger Basis: Gesamtkanten = 3n.", ["15", "10", "12", "20"], "5 nach oben + 5 nach unten + 5 vertikal = 3 × 5 = 15 Kanten."],
    "TSR2_09": ["Wie viele Eckpunkte hat ein fünfeckiges Prisma?", "Das Prisma dupliziert die Eckpunkte des Basispolygons.", ["10", "12", "8", "15"], "5 Spikes pro Base × 2 Bases = 10 Spikes."],
    "TSR2_10": ["Wie viele Kanten hat eine Pyramide mit quadratischer Grundfläche?", "Zählen Sie die Kanten der Basis, dann die Kanten von den Ecken der Basis bis zur Oberseite.", ["8", "5", "6", "10"], "4 Kanten an der Basis + 4 Seitenkanten nach oben = 8 Kanten."],
    "TSR2_11": ["Wie viele Eckpunkte hat eine Pyramide mit quadratischer Grundfläche?", "Vergessen Sie nicht den Top-Tipp!", ["5", "4", "6", "8"], "4 Ecken an der Basis + 1 Oberteil = 5 Oberteile."],
    "TSR2_12": ["Wie viele Flächen hat eine Pyramide mit quadratischer Grundfläche?", "Zählen Sie die Basis und jede dreieckige Seitenfläche.", ["5", "4", "6", "8"], "1 quadratische Basis + 4 dreieckige Flächen = 5 Flächen."],
    "TSR2_13": ["Wie viele Kanten hat ein sechseckiges Prisma?", "Formel: Kanten = 3 × Anzahl der Seiten der Basis.", ["18", "12", "24", "15"], "6 + 6 + 6 = 3 × 6 = 18 Kanten."],
    "TSR2_14": ["Wie viele Eckpunkte hat ein sechseckiges Prisma?", "Jede sechseckige Basis hat 6 Ecken.", ["12", "8", "6", "18"], "6 Spikes pro Base × 2 Bases = 12 Spikes."],
    "TSR2_15": ["Wenn 5 identische Würfel mit gemeinsamen Flächen in einer Reihe stehen, wie viele Flächen sind dann insgesamt sichtbar (einschließlich der Unterseite)?", "5 Würfel = 30 Flächen. Wie viele Gelenke und wie viele Gesichter verbergen sich jeweils?", ["22", "20", "24", "26"], "30 Flächen − 4 Gelenke × 2 = 30 − 8 = 22 sichtbar."],
    "TSR2_16": ["Wie viele Flächen hat ein achteckiges Prisma?", "Prismenformel: n + 2 Flächen für n-seitige Basis.", ["10", "8", "12", "16"], "2 achteckige Grundflächen + 8 rechteckige Seitenflächen = 10 Flächen."],
    "TSR2_17": ["Wie viele Kanten hat ein achteckiges Prisma?", "Formel: 3n Kanten für Basis mit n Seiten.", ["24", "16", "20", "32"], "3 × 8 = 24 Kanten."],
    "TSR2_18": ["Wie viele Eckpunkte hat eine dreieckige Pyramide (Tetraeder)?", "Dreieckige Basis und ein Punkt darüber.", ["4", "3", "5", "6"], "Tetraeder: 3 Eckpunkte an der Basis + 1 Eckpunkt = 4 Eckpunkte."],
    "TSR2_19": ["Eulers Formel: V − E + F = 2 für konvexe Polyeder (E = Anzahl der Kanten). Wenn ein Polyeder 6 Eckpunkte und 12 Kanten hat, wie viele Flächen hat es?", "Neu anordnen: F = 2 − V + E.", ["8", "6", "10", "7"], "F = 2 − 6 + 12 = 8 Flächen (z. B. regelmäßiger Würfel oder Oktaeder)."],
    "TSR2_20": ["Wie viele Diagonalen hat ein Quadrat?", "Eine Diagonale verbindet zwei nicht benachbarte Eckpunkte. Das Quadrat hat 4 Eckpunkte.", ["2", "4", "1", "3"], "Das Quadrat hat zwei Diagonalen, die jeweils gegenüberliegende Ecken verbinden."],
    "TSR3_01": ["Ein 3×3×3 Würfel wird auf allen Seiten bemalt und dann in 27 kleine Würfel geschnitten. Wie viele Würfel haben mindestens eine bemalte Seite?", "Nur der Würfel genau in der Mitte des 3×3×3-Rasters hat keine Farbe. Wie viele Würfel befinden sich nicht in der Mitte?", ["26", "24", "20", "27"], "Ein einzelner Würfel (die Mitte) hat 0 bemalte Flächen. Also haben 27 − 1 = 26 mindestens ein bemaltes Gesicht."],
    "TSR3_02": ["Ein 3×3×3 Würfel wird auf allen Seiten bemalt und in 27 kleine Würfel geschnitten. Wie viele bemalte Flächen haben alle 27 Würfel insgesamt?", "Jede der 6 Flächen des großen Würfels ist ein 3×3-Gitter, also 9 bemalte Einheitsflächen pro Fläche.", ["54", "48", "36", "27"], "6 Flächen × 9 = 54 bemalte Einheitsflächen."],
    "TSR3_03": ["Der bemalte 3×3×3 Würfel wird in 27 kleine Würfel geschnitten. Wie viele Würfel haben höchstens ein bemaltes Gesicht?", "Zählen Sie die Würfel mit 0 bemalten Flächen und genau 1 und addieren Sie dann.", ["7", "6", "8", "12"], "1 Würfel mit 0 Flächen (der Mitte) + 6 Würfel mit genau 1 (den Mittelpunkten der Flächen). Gesamt: 1 + 6 = 7."],
    "TSR3_04": ["Der bemalte 3×3×3 Würfel wird in 27 kleine Würfel geschnitten. Wie viele Würfel haben mindestens zwei bemalte Flächen?", "Es sind die Eckwürfel (3 Seiten) und die am Rand (2 Seiten).", ["20", "12", "8", "18"], "8 Ecken (3 bemalt) + 12 Kanten × 1 mittlerer zweiseitiger Würfel = 20 Würfel mit 2 oder mehr bemalten Flächen."],
    "TSR3_05": ["Welche Form hat der Schnitt, wenn Sie einen Würfel mit einer Ebene parallel zu einer der Flächen schneiden?", "Wenn man parallel zu einer quadratischen Fläche schneidet, erhält man eine mit dieser Fläche kongruente Form.", ["Quadratisch", "Rechteck", "Dreieck", "Sechseck"], "Die Ebene parallel zu einer Fläche schneidet vier gleiche Kanten und ergibt ein Quadrat."],
    "TSR3_06": ["Welche Form hat der Schnitt, wenn man einen Zylinder mit einer Ebene senkrecht zu seiner Achse schneidet?", "Die Achse verläuft durch die Mittelpunkte der beiden kreisförmigen Grundflächen.", ["Kreis", "Ellipse", "Rechteck", "Oval"], "Der Schnitt senkrecht zur Achse erfolgt parallel zu den Grundflächen – Sie erhalten einen Kreis."],
    "TSR3_07": ["Welche Form erhält man, wenn man einen Kegel mit einer Ebene parallel zur kreisförmigen Grundfläche schneidet?", "Die Basis des Kegels ist ein Kreis. Paralleles Schneiden ergibt eine ähnliche Form.", ["Kreis", "Ellipse", "Dreieck", "Parabel"], "Die zur Grundfläche parallele Ebene schneidet den Kegel auf einem Kreis (kleiner als die Grundfläche)."],
    "TSR3_08": ["Wie viele Eckpunkte hat eine Kugel?", "Oben treffen die Kanten aufeinander. Hat die Kugel Kanten?", ["0", "1", "2", "Unendlich"], "Die Kugel ist eine glatte Oberfläche, ohne Kanten, also ohne Spitzen."],
    "TSR3_09": ["Wie viele Kanten hat eine Kugel?", "Die Kante ist der Abschnitt, an dem zwei flache Flächen aufeinandertreffen.", ["0", "1", "2", "Unendlich"], "Die Kugel hat keine flachen Flächen und daher keine Kanten."],
    "TSR3_10": ["Wie viele Flächen hat eine sechseckige Pyramide?", "Die Pyramide hat eine Basis und dreieckige Seitenflächen – eine pro Seite der Basis.", ["7", "6", "8", "12"], "1 sechseckige Basis + 6 seitliche dreieckige Flächen = 7 Flächen."],
    "TSR3_11": ["Wie viele Kanten hat eine sechseckige Pyramide?", "Zählen Sie die Kanten der Basis und die Kanten von jedem Scheitelpunkt der Basis bis zum Scheitelpunkt der Pyramide.", ["12", "6", "8", "18"], "6 Kanten an der Basis + 6 Seitenkanten nach oben = 12 Kanten."],
    "TSR3_12": ["Wie viele Eckpunkte hat eine sechseckige Pyramide?", "Zählen Sie die Eckpunkte der Basis und den eindeutigen oberen Scheitelpunkt.", ["7", "6", "8", "12"], "6 Spikes an der Basis + 1 Spike = 7 Spikes. (Euler-Check: 7 − 12 + 7 = 2 ✓)"],
    "TSR3_13": ["Welche Form kann der Abschnitt haben, wenn man einen Würfel von der Mitte einer Kante zur Mitte der gegenüberliegenden parallelen Kante schneidet?", "Wenn man zwischen zwei parallelen Kanten schneidet, erhält man ein ebenes Viereck.", ["Rechteck", "Dreieck", "Pentagon", "Kreis"], "Die Ebene ergibt durch zwei gegenüberliegende parallele Kanten einen rechteckigen Querschnitt."],
    "TSR3_14": ["Wie viele Flächen hat eine fünfeckige Grundpyramide?", "1 Basis + Seitenflächen (eine pro Seite der Basis).", ["6", "5", "7", "10"], "1 fünfeckige Basis + 5 dreieckige Flächen = 6 Flächen."],
    "TSR3_15": ["Wie viele Kanten hat eine Pyramide mit fünfeckiger Grundfläche?", "Für Pyramide mit n-seitiger Grundfläche: 2n Kanten.", ["10", "5", "8", "15"], "5 Kanten an der Basis + 5 Seiten = 10 Kanten."],
    "TSR3_16": ["Wie viele Eckpunkte hat eine fünfeckige Grundpyramide?", "Die Eckpunkte der Basis plus der obere Scheitelpunkt.", ["6", "5", "7", "10"], "5 Spikes an der Basis + 1 Spike = 6 Spikes. (Prüfung: 6 − 10 + 6 = 2 ✓)"],
    "TSR3_17": ["Wie viele Flächen hat ein Polyeder unter Verwendung der Eulerschen Formel (V − E + F = 2), wenn es 5 Eckpunkte und 8 Kanten hat?", "Lösen Sie nach F auf: F = 2 − V + E.", ["5", "4", "6", "7"], "F = 2 − 5 + 8 = 5 (z. B. Pyramide mit quadratischer Grundfläche: 5 Eckpunkte, 8 Kanten, 5 Flächen)."],
    "TSR3_18": ["Wie viele Diagonalen hat ein regelmäßiges Sechseck?", "Für ein Polygon mit n Seiten: n(n − 3) / 2.", ["9", "6", "12", "3"], "Diagonalen = 6 × (6 − 3) / 2 = 9."],
    "TSR3_19": ["Wie viele bemalte Flächen haben in einem bemalten 3×3×3-Würfel, der in 27 Würfel geschnitten ist, insgesamt nur die 8 Eckwürfel?", "Jeder Eckwürfel hat genau 3 bemalte Flächen.", ["24", "8", "12", "18"], "8 Ecken × 3 Flächen = 24 bemalte Flächen an den Ecken."],
    "TSR3_20": ["Wie viele Diagonalen hat ein regelmäßiges Fünfeck?", "Verwenden Sie n(n − 3) / 2 mit n = 5.", ["5", "4", "6", "3"], "Diagonalen = 5 × (5 − 3) / 2 = 5."],
    "TSR4_01": ["Ein 4×4×4 Würfel wird auf allen Seiten bemalt und dann in 64 kleine Würfel geschnitten. Wie viele Würfel haben mindestens eine bemalte Seite?", "Der unbemalte Innenraum bildet einen kleineren Würfel mit der Seitenlänge (4 − 2) = 2.", ["56", "48", "52", "60"], "Würfel mit 0 Farbe innen = 2³ = 8. Mit mindestens 1 Seite bemalt: 64 − 8 = 56."],
    "TSR4_02": ["Der bemalte 4×4×4 Würfel wird in 64 kleine Würfel geschnitten. Wie viele Würfel haben mindestens zwei bemalte Flächen?", "Eckwürfel (3-seitig) und Kantenwürfel (2-seitig). Sammle sie.", ["32", "24", "36", "28"], "Ecken: 8. Kanten: 12 × 2 mittlere Würfel = 24. Gesamt: 8 + 24 = 32."],
    "TSR4_03": ["Der bemalte 4×4×4 Würfel wird in 64 kleine Würfel geschnitten. Wie viele bemalte Flächen haben alle Würfel insgesamt?", "Jede der 6 Seiten des großen Würfels ist ein 4×4-Gitter.", ["96", "64", "72", "108"], "6 × 16 = 96. (Überprüfen Sie: 8 × 3 + 24 × 2 + 24 × 1 = 96 ✓)"],
    "TSR4_04": ["Der bemalte 4×4×4 Würfel wird in 64 kleine Würfel geschnitten. Wie viele Würfel haben höchstens ein bemaltes Gesicht?", "Addiere die Würfel mit 0 bemalten Flächen und genau 1.", ["32", "24", "28", "36"], "0 lackiert: 8 (Innenraum 2×2×2). 1 gefärbt: 24 (Mittelflächen). Gesamt: 32."],
    "TSR4_05": ["Wenn Sie einen Eckwürfel von einem 3×3×3-Würfel entfernen, wie viele Flächen der Einheitswürfel sind auf dem verbleibenden Körper (einschließlich der Unterseite) sichtbar?", "Durch das Entfernen der Ecke verlieren Sie drei Außenflächen, legen aber drei zuvor verborgene Innenflächen frei.", ["54", "51", "57", "48"], "Anfangsfläche: 6 × 9 = 54. An der Ecke: −3 außen + 3 neu sichtbar innen = 0 netto. Ich bleibe 54."],
    "TSR4_06": ["Wie viele Diagonalen hat ein regelmäßiges Achteck?", "Formel n(n − 3) / 2 mit n = 8.", ["20", "16", "24", "8"], "Diagonalen = 8 × 5 / 2 = 20."],
    "TSR4_07": ["Wie viele Raumdiagonalen hat ein Würfel? (Die Raumdiagonale verläuft durch den Innenraum von einem Scheitelpunkt zum gegenüberliegenden Scheitelpunkt.)", "Der Würfel hat 8 Eckpunkte. Jede Raumdiagonale verbindet einen Scheitelpunkt mit seinem Gegenstück.", ["4", "6", "8", "12"], "Der Würfel hat 4 Raumdiagonalen, jeweils durch die Mitte."],
    "TSR4_08": ["Wie viele Flächendiagonalen hat ein Würfel insgesamt?", "Jedes Gesicht ist quadratisch. Wie viele Diagonalen hat das Quadrat? Mit 6 multiplizieren.", ["12", "6", "8", "24"], "6 Flächen × 2 Diagonalen = 12 Diagonalen in Flächen."],
    "TSR4_09": ["Wie viele Flächen hat ein regelmäßiges Oktaeder (zwei an der Basis zusammengeklebte quadratische Pyramiden)?", "Jede Pyramide hat 4 dreieckige Flächen. Die gemeinsame quadratische Basis befindet sich im Inneren.", ["8", "6", "12", "20"], "Das regelmäßige Oktaeder hat 8 gleichseitige Dreiecksflächen."],
    "TSR4_10": ["Wie viele Kanten hat ein regelmäßiges Oktaeder?", "Verwenden Sie die Euler-Formel, wenn Sie wissen, dass V = 6 und F = 8 ist.", ["12", "8", "6", "24"], "E = V + F − 2 = 6 + 8 − 2 = 12 Kanten."],
    "TSR4_11": ["Wie viele Eckpunkte hat ein regelmäßiges Oktaeder?", "Stellen Sie sich zwei Pyramiden vor, die an der Basis verbunden sind. Zählen Sie die deutlichen Spitzen.", ["6", "8", "12", "4"], "4 Eckpunkte um den quadratischen Äquator + 1 Eckpunkt nach oben + 1 nach unten = 6."],
    "TSR4_12": ["Wenn 8 Einheitswürfel einen 2×2×2-Würfel bilden, wie viele Flächen der Einheitswürfel sind außen (einschließlich der Unterseite) sichtbar?", "Das Ergebnis ist ein Würfel mit Seite 2. Gesamtfläche in Einheitsflächen?", ["24", "28", "32", "20"], "6 × (2×2) = 24 Einheitsflächen."],
    "TSR4_13": ["Ein regelmäßiges Dodekaeder hat 12 fünfeckige Flächen und 30 Kanten. Wie viele Eckpunkte hat die Euler-Formel?", "V = 2 + E − F.", ["20", "12", "24", "30"], "V = 2 + 30 − 12 = 20 Eckpunkte."],
    "TSR4_14": ["A regular icosahedron has 20 triangular faces and 12 vertices. Wie viele Kanten hat es?", "E = V + F − 2.", ["30", "20", "24", "36"], "E = 12 + 20 − 2 = 30 Kanten."],
    "TSR4_15": ["Wie viele bemalte Flächen haben die 8 Eckwürfel in einem bemalten 4×4×4-Würfel insgesamt?", "Jeder Eckwürfel hat genau 3 bemalte Flächen, unabhängig von der Größe des großen Würfels.", ["24", "8", "12", "32"], "8 × 3 = 24."],
    "TSR4_16": ["Wie viele bemalte Flächen haben die Kantenwürfel (diejenigen mit genau 2 bemalten Flächen) im gleichen 4×4×4-Würfel?", "Wie viele Würfel sind auf den Kanten, dann multiplizieren Sie mit 2.", ["48", "24", "36", "60"], "24 Würfel auf Kanten (12 Kanten × 2), jeweils mit 2 bemalten Flächen: 24 × 2 = 48."],
    "TSR4_17": ["Welche Form hat der Schnitt, wenn man einen Würfel mit einer Ebene durch drei Kanten schneidet, die am gleichen Scheitelpunkt beginnen?", "Die drei Mittelwerte sind von der Ecke gleich weit entfernt. Welches Dreieck hat alle gleiche Seiten?", ["Gleichseitiges Dreieck", "Quadratisch", "Rechtwinkliges Dreieck", "Regelmäßiges Sechseck"], "Der Hobel schneidet die drei Eckkanten gleichmäßig – Sie erhalten ein gleichseitiges Dreieck."],
    "TSR4_18": ["Wie viele Diagonalen hat ein regelmäßiges Zehneck (10 Seiten)?", "Formel: n(n − 3) / 2.", ["35", "30", "40", "25"], "10 × 7 / 2 = 35."],
    "TSR4_19": ["Ein Prisma hat genau 10 Eckpunkte. Welche Form hat die Basis?", "Das n-seitige Grundprisma hat 2n Eckpunkte.", ["Pentagon", "Quadratisch", "Sechseck", "Dreieck"], "2n = 10 → n = 5. Die Basis ist ein Fünfeck."],
    "TSR4_20": ["Eine Pyramide hat genau 7 Flächen. Welche Form hat die Basis?", "Die n-seitige Grundpyramide hat n + 1 Flächen.", ["Sechseck", "Pentagon", "Siebeneck", "Achteck"], "n + 1 = 7 → n = 6. Die Basis ist ein Sechseck."],
    "TSR5_01": ["Ein 5×5×5 Würfel wird auf allen Seiten bemalt und dann in 125 kleine Würfel geschnitten. Wie viele Würfel haben genau 2 bemalte Flächen?", "Die Würfel haben an den Kanten (nicht an den Ecken) zwei bemalte Flächen. Formel: 12(n − 2).", ["36", "24", "48", "30"], "12 × (5 − 2) = 36."],
    "TSR5_02": ["Der bemalte 5×5×5 Würfel wird in 125 kleine Würfel geschnitten. Wie viele Würfel haben genau drei Flächen bemalt?", "Nur die Eckwürfel haben 3 bemalte Gesichter. Wie viele Ecken hat ein Würfel?", ["8", "12", "20", "6"], "Jeder Würfel hat 8 Ecken. Also 8 Würfel mit genau 3 bemalten Flächen."],
    "TSR5_03": ["Der bemalte 5×5×5 Würfel wird in 125 kleine Würfel geschnitten. Wie viele Würfel haben mindestens eine bemalte Seite?", "Subtrahieren Sie die Würfel darin völlig unbemalt: (n − 2)³.", ["98", "96", "100", "90"], "Innen = 3³ = 27. 125 − 27 = 98."],
    "TSR5_04": ["Der bemalte 5×5×5 Würfel wird in 125 kleine Würfel geschnitten. Wie viele bemalte Flächen haben alle Würfel insgesamt?", "Jede der 6 Flächen des großen Würfels ist ein 5×5-Gitter.", ["150", "125", "144", "162"], "6 × 25 = 150."],
    "TSR5_05": ["Ein bemalter 6×6×6 Würfel wird in 216 kleine Würfel geschnitten. Wie viele haben genau 2 Gesichter bemalt?", "12(n − 2) mit n = 6.", ["48", "36", "60", "24"], "12 × 4 = 48."],
    "TSR5_06": ["Der bemalte 6×6×6 Würfel wird in 216 kleine Würfel geschnitten. Wie viele haben genau ein Gesicht bemalt?", "6(n − 2)² mit n = 6.", ["96", "72", "108", "84"], "6 × 16 = 96."],
    "TSR5_07": ["Der bemalte 6×6×6 Würfel wird in 216 kleine Würfel geschnitten. Wie viele haben überhaupt keine Gesichtsbemalung?", "Innerer Block: (n − 2)³.", ["64", "48", "36", "27"], "(6 − 2)³ = 64."],
    "TSR5_08": ["Der bemalte 6×6×6 Würfel wird in 216 kleine Würfel geschnitten. Wie viele haben genau 3 Gesichter bemalt?", "Die Ecken sind immer 8, unabhängig von der Größe.", ["8", "12", "6", "24"], "8 Würfel mit 3 bemalten Gesichtern. (Prüfung: 8+48+96+64=216 ✓)"],
    "TSR5_09": ["Der bemalte 6×6×6 Würfel wird in 216 kleine Würfel geschnitten. Wie viele bemalte Einheitenflächen haben sie insgesamt?", "Jede Seite des großen Würfels ist ein 6×6-Gitter.", ["216", "200", "192", "240"], "6 × 36 = 216."],
    "TSR5_10": ["Wie viele 2 bemalte Gesichter gibt es in einem 10×10×10 bemalten Würfel, der in 1000 Würfel geschnitten ist?", "12(n − 2) für die Würfel auf den Kanten.", ["96", "120", "80", "108"], "12 × 8 = 96."],
    "TSR5_11": ["Wie viele kleine Würfel haben im selben 10×10×10-Würfel genau eine bemalte Fläche?", "6(n − 2)² für die Mittelpunkte der Flächen.", ["384", "360", "400", "480"], "6 × 64 = 384."],
    "TSR5_12": ["Wie viele kleine Würfel haben überhaupt keine Gesichtsbemalung?", "Der Innenraum ist ein Würfel mit der Seite (n − 2).", ["512", "480", "500", "343"], "(10 − 2)³ = 512."],
    "TSR5_13": ["Welche dieser Formen KANN der Querschnitt eines Würfels sein?", "Eine Ebene kann höchstens 6 Flächen schneiden. Können Sie die 6 Kanten durchgehen?", ["Regelmäßiges Sechseck", "Regelmäßiges Pentagon", "Regelmäßiges Achteck", "Ellipse"], "Durch 6 Kanten erhält man ein regelmäßiges Sechseck. Die Symmetrie des Würfels ergibt keine Fünfecke, Achtecke (max. 6 Seiten) oder Kurven."],
    "TSR5_14": ["Wie viele Seiten hat ein ebener Würfelabschnitt maximal?", "Das Schnittpolygon erhält für jede Schnittfläche eine Seite.", ["6", "4", "8", "12"], "Der Würfel hat 6 Flächen – höchstens ein Sechseck (6 Seiten)."],
    "TSR5_15": ["Das regelmäßige Dodekaeder hat 12 fünfeckige Flächen. Jede Fläche hat 5 Kanten, aber jede Kante ist zwei Flächen gemeinsam. Wie viele Kanten hat es?", "12 × 5 Kantenplätze, jede Kante wird doppelt gezählt.", ["30", "24", "36", "60"], "12 × 5 / 2 = 30 Kanten."],
    "TSR5_16": ["Wie viele 2 bemalte Gesichter gibt es in einem 7×7×7 bemalten Würfel, der in 343 Würfel geschnitten wurde?", "12(n − 2) mit n = 7.", ["60", "48", "72", "36"], "12 × 5 = 60."],
    "TSR5_17": ["Wie viele kleine Würfel im 7×7×7-Würfel haben kein bemaltes Gesicht?", "(n − 2)³.", ["125", "64", "100", "27"], "5³ = 125."],
    "TSR5_18": ["Für den n×n×n bemalten Würfel beträgt die Anzahl der Würfel mit genau einer bemalten Fläche 6(n − 2)². Warum steht in der Gleichung 96?", "6(n − 2)² = 96 → (n − 2)² = 16.", ["6", "5", "7", "8"], "n − 2 = 4 → n = 6."],
    "TSR5_19": ["Wie viele Seiten hat ein Schnitt durch ein dreieckiges Prisma maximal?", "Das dreieckige Prisma hat 5 Flächen (2 Dreiecke + 3 Rechtecke). Kann ein Plan alle 5 streichen?", ["5", "4", "3", "6"], "Eine schiefe Ebene kann beide Grundflächen und die 3 Seitenflächen schneiden – fünfeckiger Querschnitt, maximal 5."],
    "TSR5_20": ["Wie viele bemalte Flächeneinheiten haben die 343 Würfel im bemalten 7×7×7-Würfel insgesamt?", "Jede der 6 Seiten des großen Würfels ist ein 7×7-Gitter.", ["294", "252", "300", "343"], "6 × 49 = 294."],
    "TMP1_1": ["Ein Bauer hat 12 Schafe. Alle bis auf 5 sterben. Wie viele Schafe sind noch übrig?", "Konzentrieren Sie sich auf „alle bis auf 5“.", ["5", "7", "12", "0"], "„Alle bis auf 5 sterben“ bedeutet, dass 5 überleben. Die Antwort ist 5, nicht 12 minus 5."],
    "TMP1_2": ["Bei einem Rennen überholt man den Drittplatzierten. Wo bist du gerade?", "Was passiert, wenn Sie jemanden überholen – nehmen Sie seinen Platz ein?", ["Der 3", "Der 2", "Der 4", "Der 1"], "Wenn Sie die Person auf dem 3. Platz überholen, nehmen Sie deren Platz ein – Sie werden Dritter, nicht Zweiter."],
    "TMP1_3": ["Wie viele Geburtstage hat ein Mensch im Durchschnitt?", "Du wirst nur einmal geboren.", ["1", "Ungefähr 75", "365", "Es kommt auf das Alter an"], "Jeder hat nur einen Geburtstag – den Tag seiner Geburt. Der Rest sind Jahrestage dieses Tages."],
    "TMP1_4": ["Wenn du 5 Orangen hast und 2 nimmst, wie viele hast DU?", "Wer hat die Orangen genommen?", ["2", "3", "5", "0"], "Du hast 2 Orangen genommen, also hast du 2. Die Frage ist, wie viele du hast, nicht wie viele noch übrig sind."],
    "TMP1_5": ["A ist der Vater von B, aber B ist nicht der Sohn von A. Wie ist das möglich?", "Alle Geschlechtsvarianten für B.", ["B ist die Tochter von A", "A ist nicht wirklich der Vater von B", "B wird übernommen", "Sie sind Stiefverwandte"], "B ist ein Mädchen – sie ist die Tochter von A. Nicht jedes Kind ist ein Junge."],
    "TMP1_6": ["Wie oft können Sie 10 von 100 subtrahieren?", "Sind nach dem ersten Drop noch 100 übrig?", ["1", "10", "9", "Aus der Unendlichkeit"], "Nur einmal – danach haben Sie 90 und subtrahieren 10 von 90, nicht 100."],
    "TMP1_7": ["Wenn ein Hahn Eier auf das Dach legt, in welche Richtung rollt das Ei?", "Was genau ist ein Hahn?", ["Hähne legen keine Eier", "Links", "Richtig", "Bleib auf"], "Hähne sind Männchen und keine Eier. Die Prämisse ist unmöglich."],
    "TMP1_8": ["Was wiegt mehr: ein Pfund Federn oder ein Pfund Ziegel?", "Schauen Sie sich die Maßeinheit genau an.", ["Ebenso", "Die Ziegel", "Federn", "Es kommt darauf an"], "Ein Pfund ist ein Pfund, unabhängig vom Material. Beide wiegen genau ein Pfund."],
    "TMP1_9": ["Ein Hemd kostete 50 $ und es gibt 50 % Rabatt. Wie viel zahlen Sie?", "Berechnet 50 % des Originalpreises.", ["25 $", "50 $", "30 $", "15 $"], "50 % von 50 $ = 25 $."],
    "TMP1_10": ["Sie befinden sich in einem dunklen Raum mit einer Kerze, einer Öllampe und einem Kamin. Sie haben nur eine Übereinstimmung. Was zündest du beim ersten Mal an?", "Man muss vor allem etwas anzünden.", ["Das Spiel", "Die Kerze", "Die Lampe", "Der Kamin"], "Zuerst müssen Sie das Streichholz anzünden, damit Sie den Rest anzünden können."],
    "TMP1_11": ["Direkt an der Grenze zweier Länder stürzt ein Flugzeug ab. Wo begräbt man die Überlebenden?", "Lesen Sie sorgfältig: Wen begraben wir?", ["Begrabe die Überlebenden nicht", "Im Abflugland", "Im Zielland", "An der Grenze"], "Überlebende sind am Leben – begraben Sie sie nicht."],
    "TMP1_12": ["Wie viele Tiere jeder Art nahm Moses mit in die Arche?", "Überprüfen Sie den Namen in der Frage.", ["Keiner – es war Noah, nicht Moses", "2", "7", "1"], "Moses hatte keine Arche – Noah hatte sie. Die Frage verwendet den falschen Namen, um Sie in die Irre zu führen."],
    "TMP1_13": ["Auf einem Zaun sitzen 10 Vögel. Zieh eins. Wie viele sind noch am Zaun?", "Wie reagieren die anderen auf die Schießerei?", ["0", "9", "10", "1"], "Der Lärm macht ihnen allen Angst. Es ist keines mehr übrig."],
    "TMP1_14": ["Ein Bauer hat 20 Kühe. Alle bis auf 12 sterben. Wie viele sind noch übrig?", "„Alle bis auf 12“.", ["12", "8", "20", "0"], "Ich überlebe 12."],
    "TMP1_15": ["Was geht immer hoch und nie runter?", "Etwas, das nur mit der Zeit wächst.", ["Dein Alter", "Ein Ballon", "Die Sonne", "Die Temperatur"], "Das Alter nimmt nur zu."],
    "TMP1_16": ["Ein Mädchen schlägt den Ball aus 3 m Entfernung. Es kommt zu ihr zurück, ohne Wand, ohne andere Person, ohne Spin. Wie?", "Auf welche Weise hat er sie geschlagen?", ["Er schlug sie senkrecht nach oben", "Der Wind", "Er sprang vom Baum", "Der Hang"], "Er trat sie hoch; Die Schwerkraft brachte es zurück."],
    "TMP1_17": ["Was hat einen Kopf und einen Schwanz, aber keinen Körper?", "Gewöhnliche Gegenstände, keine Tiere.", ["Eine Münze", "Eine Schlange", "Eine Nadel", "Ein Komet"], "Die Münze hat ein Gesicht (Kopf) und einen Schwanz (Schwanz), keinen Körper."],
    "TMP1_18": ["Der Arzt gibt Ihnen 5 Tabletten: jede Stunde eine. Wie lange dauert die Behandlung?", "Wann nimmst du deine erste Pille?", ["4 Stunden", "5 Stunden", "6 Stunden", "3 Stunden"], "Stunde 0, 1, 2, 3, 4 – die letzten 4 Stunden zwischen eins und fünf. Insgesamt 4 Stunden ab Beginn."],
    "TMP1_19": ["Du hast eine Schüssel mit 6 Eiern und nimmst 2 heraus. Wie viele hast du?", "Wer hat die Eier genommen?", ["2", "4", "6", "0"], "Du hast 2 Eier genommen. In der Schüssel sind noch 4 übrig, aber du hast 2."],
    "TMP1_20": ["Ein Junge ist 4 Jahre alt, seine Schwester ist halb so alt wie er. Wenn der Junge 100 Jahre alt ist, wie alt ist dann die Schwester?", "Der Altersunterschied bleibt gleich.", ["98", "50", "100", "96"], "Die Schwester ist 2 Jahre jünger (4÷2=2). 100 − 2 = 98."],
    "TMP2_1": ["Ein Stift und ein Notizbuch kosten zusammen 1,10 $. Das Notizbuch kostet 1,00 $ mehr als der Stift. Wie viel kostet der Stift?", "Sei x der Preis des Stifts; Das Notizbuch ist x + 1,00 $.", ["0,05 $", "0,10 $", "1,00 $", "0,50 $"], "x + (x + 1) = 1,10 → 2x = 0,10 → x = $0,05."],
    "TMP2_2": ["Der Arzt gibt Ihnen 3 Tabletten: alle 45 Minuten eine. Wie lange dauert es?", "Wann nimmst du deine erste Pille?", ["90 Minuten", "135 Minuten", "45 Minuten", "120 Minuten"], "Bei 0, 45 und 90 Minuten vergehen insgesamt 90 Minuten."],
    "TMP2_3": ["5 Arbeiter bauen in 5 Tagen 5 Wände. Wie lange brauchen 10 Arbeiter, um 10 Mauern zu bauen?", "Wie viel kostet ein Arbeiter, um eine Mauer zu bauen?", ["5 Tage", "10 Tage", "2,5 Tage", "1 Tag"], "Jeder baut in 5 Tagen 1 Mauer. 10 Personen, 10 parallele Wände – ebenfalls 5 Tage."],
    "TMP2_4": ["Zwei Münzen ergeben 30 Cent. Einer ist kein Nickel (5¢). Welche Währungen gibt es?", "„Das eine ist kein Nickel“ – was ist das andere?", ["25¢ und 5¢ (Viertel + Nickel)", "Zwei 10¢-Münzen", "50¢", "10¢ und 5¢"], "Einer ist ein Viertel (25¢), kein Nickel; der andere ist Nickel (5¢). Insgesamt 30¢."],
    "TMP2_5": ["Multiplizieren Sie alle Ziffern auf einer Telefontastatur (0–9). Was ist das Produkt?", "Was passiert, wenn man mit einer bestimmten Zahl multipliziert?", ["0", "3.628.800", "362.880", "45"], "Unter den Zahlen ist 0. Jedes Produkt, das 0 enthält, ist 0."],
    "TMP2_6": ["Eine Familie besteht aus 4 Jungen und 3 Mädchen. Jeder Junge hat genauso viele Schwestern wie Brüder. Jedes Mädchen hat doppelt so viele Brüder wie Schwestern. Wie viele Kinder gibt es?", "Zählen Sie aus der Perspektive jedes Kindes.", ["7", "8", "6", "10"], "Junge: 3 Brüder, 3 Schwestern ✓. Mädchen: 4 Brüder, 2 Schwestern (4 = 2×2) ✓. Insgesamt 7."],
    "TMP2_7": ["Ein elektrischer Zug fährt nach Norden. Der Wind weht aus westlicher Richtung. Wohin geht der Rauch?", "Welchen Antrieb hat der Zug?", ["Es gibt keinen Rauch", "Westen", "Norden", "Schätzung:"], "Der elektrische Zug verbrennt keinen Treibstoff – er erzeugt keinen Rauch."],
    "TMP2_8": ["8 Leute bauen in 10 Stunden eine Mauer. Wie lange dauert es mit 4 Personen?", "Die Hälfte der Leute verdoppelt die Zeit.", ["20 Stunden", "5 Stunden", "40 Stunden", "10 Stunden"], "10 × 2 = 20 Stunden."],
    "TMP2_9": ["Wie viele Monate im Jahr haben (mindestens) 30 Tage?", "Manche Monate haben mehr als 30 Tage.", ["11", "4", "6", "7"], "Alle Monate außer Februar haben mindestens 30 Tage. Also 11 Monate."],
    "TMP2_10": ["Graben Sie 6 Löcher: 3 große und 3 kleine. Wie viele Löcher hast du?", "Ändert die Größe die Tatsache, dass es sich um ein Loch handelt?", ["6", "3", "9", "0"], "Alle 6 Löcher."],
    "TMP2_11": ["Können Sie drei Tage hintereinander ohne Montag, Dienstag, Mittwoch, Donnerstag, Freitag, Samstag, Sonntag nennen?", "Relative Begriffe, keine Eigennamen.", ["Gestern, heute und morgen", "Tag 1, 2, 3", "Unmöglich", "Morgens, mittags, abends"], "Gestern, heute, morgen sind immer drei aufeinanderfolgende Tage."],
    "TMP2_12": ["Wie viel ist 1/2 von 2/3 von 3/4 von 4/5 von 100?", "Vereinfachen Sie Brüche vor der Multiplikation.", ["20", "10", "50", "25"], "1/2 × 2/3 × 3/4 × 4/5 = 1/5. 1/5 × 100 = 20."],
    "TMP2_13": ["Eine Seerose verdoppelt jeden Tag ihre Oberfläche. Am 20. Tag füllen Sie den See. An welchem ​​Tag wurden genau 25 % abgedeckt?", "Gehen Sie rückwärts: Jeden Tag durch 2 dividieren.", ["Tag 18", "Tag 5", "Tag 15", "Tag 10"], "Tag 20: 100 %. Tag 19: 50 %. Tag 18: 25 %."],
    "TMP2_14": ["Ein Ziegel wiegt 1 kg plus die Hälfte des Ziegelgewichts. Wie viel wiegt es?", "Sei b das Gewicht: b = 1 + b/2.", ["2 kg", "1,5 kg", "3 kg", "1 kg"], "b/2 = 1 → b = 2 kg."],
    "TMP2_15": ["6 Männer graben 6 Löcher in 6 Stunden. Wie lange brauchen 3 Personen, um 3 Löcher zu graben?", "Wie lange braucht ein Mensch für ein Loch?", ["6 Stunden", "3 Stunden", "12 Stunden", "9 Stunden"], "Jeder gräbt in 6 Stunden 1 Loch. 3 Personen, 3 Löcher parallel – ebenfalls 6 Stunden."],
    "TMP2_16": ["Wie lautet der nächste Buchstabe: O, T, T, F, F, S, S, ?", "Auf Englisch: die Initialen der Zahlen One, Two, Three…", ["E", "N", "T", "H"], "Eins, zwei, drei, vier, fünf, sechs, sieben, acht → O, T, T, F, F, S, S, E."],
    "TMP2_17": ["Du hast 8 Bälle: 7 gleich, einer schwerer. Wie viele Mindestwägungen gibt es bei einer Waage?", "Teilen Sie sich in drei Gruppen auf, nicht in zwei.", ["2", "3", "1", "4"], "3 gegen 3; dann 1 gegen 1 oder aus der schweren Gruppe. Maximal 2 Wägungen."],
    "TMP2_18": ["In einem Rennen überholt man den Letzten. Auf welchem ​​Platz sitzen Sie?", "Wer steckt hinter dem letzten?", ["Es ist unmöglich", "Der letzte", "Der Vorletzte", "Der Erste"], "Es gibt niemanden, der hinter dem Letzten steht – man kann nicht dahinter stehen, um ihn zu schlagen."],
    "TMP2_19": ["3 Katzen fangen 3 Mäuse in 3 Minuten. Wie lange brauchen 100 Katzen, um 100 Mäuse zu fangen?", "Wie viele Minuten fängt eine Katze eine Maus?", ["3 Minuten", "100 Minuten", "33 Minuten", "1 Minute"], "Jeder fängt 1 Maus in 3 Minuten. Parallel dazu auch 3 Minuten."],
    "TMP2_20": ["Welcher Bruchteil eines Tages beträgt 6 Stunden?", "Wie viele Stunden hat der Tag?", ["1/4", "1/6", "1/3", "1/2"], "6/24 = 1/4."],
    "TMP3_1": ["6 Maschinen stellen 6 Spielzeuge in 6 Minuten her. Wie lange brauchen 12 Maschinen, um 12 Spielzeuge herzustellen?", "Wie viele Minuten braucht eine Maschine, um ein Spielzeug herzustellen?", ["6 Minuten", "12 Minuten", "3 Minuten", "1 Minute"], "Jeder stellt in 6 Minuten 1 Spielzeug her. 12 Autos parallel – ebenfalls 6 Minuten."],
    "TMP3_2": ["Die Uhr zeigt 6:00 Uhr. Wie groß ist der Winkel zwischen Stundenzeiger und Minutenzeiger?", "Wohin zeigen die Zungen Punkt 6:00 Uhr?", ["180°", "90°", "120°", "360°"], "Minutenzeiger bei 12, Stundenzeiger bei 6 – gerade Linie, 180°."],
    "TMP3_3": ["Die Uhr zeigt 9:00 Uhr. Wie groß ist der Winkel zwischen den Zungen?", "Wo sehen die Zungen um Punkt 9:00 Uhr aus?", ["90°", "180°", "270°", "45°"], "Minutenzeiger bei 12, Stundenzeiger bei 9 – rechter Winkel, 90°."],
    "TMP3_4": ["In einem Raster ist Spalte 1 + Spalte 2 = Spalte 3. Zeilen: [3, 5, 8], [7, 2, 9], [4, 6, ?]. Finden Sie die fehlende Nummer.", "Wenden Sie die gleiche Regel auf die dritte Zeile an.", ["10", "8", "12", "6"], "4 + 6 = 10."],
    "TMP3_5": ["In einem Raster ist Spalte 1 × Spalte 2 = Spalte 3. Zeilen: [2, 5, 10], [3, 4, 12], [6, 3, ?]. Finden Sie die fehlende Nummer.", "Multiplizieren Sie die ersten beiden Spalten der dritten Zeile.", ["18", "9", "15", "21"], "6 × 3 = 18."],
    "TMP3_6": ["Eine Schnecke steigt tagsüber 4 m hoch und rutscht nachts 2 m hoch. Die Mauer ist 12 m lang. Wie viele Tage dauert es, um den Gipfel zu erreichen?", "Am letzten Tag kann er raus, bevor er zurückfällt.", ["5 Tage", "6 Tage", "4 Tage", "10 Tage"], "Netto +2 m pro Zyklus. Nach 4 Tagen: 8 m. Am 5. Tag Aufstieg 8+4=12 m – Ankunft vor Einbruch der Dunkelheit."],
    "TMP3_7": ["2 Personen streichen 2 Räume in 2 Stunden. Wie lange dauert es bei 4 Personen und 4 Zimmern?", "Wie viele Stunden streicht ein Mann einen Raum?", ["2 Stunden", "4 Stunden", "1 Stunde", "8 Stunden"], "Jeder streicht 1 Raum in 2 Stunden. 4 Personen, 4 Kameras parallel – ebenfalls 2 Stunden."],
    "TMP3_8": ["Sie kaufen etwas für 3 $ und verkaufen es für 5 $. Dann kaufen Sie etwas anderes für 6 $ und verkaufen es für 9 $. Wie hoch ist der Gesamtgewinn?", "Der Gewinn jeder Transaktion separat.", ["5 $", "3 $", "2 $", "6 $"], "5−3=2, 9−6=3. Insgesamt 5 $."],
    "TMP3_9": ["Ein Frosch springt 3 m vorwärts und rutscht 1 m pro Zyklus zurück. Wie viele Sprünge, bis die 10-m-Marke überschritten wird?", "Der letzte Sprung kann ohne Rückfall erfolgen.", ["5 Sprünge", "4 Sprünge", "6 Sprünge", "10 Sprünge"], "Nach 4 Zyklen: 8 m. 5. Sprung: 8+3=11 m > 10. Also 5."],
    "TMP3_10": ["Tom ist dreimal so alt wie Jim. In 10 Jahren wird Tom doppelt so alt sein wie Jim. Wie alt ist Jim jetzt?", "T = 3J; T+10 = 2(D+10).", ["10", "5", "15", "20"], "3J+10 = 2J+20 → J = 10."],
    "TMP3_11": ["Sie kaufen ein Pferd für 60 $, verkaufen es für 70 $, kaufen es für 80 $ zurück und verkaufen es für 90 $. Gesamtgewinn?", "Jede Transaktion separat.", ["20 $", "10 $", "30 $", "0 $"], "+10 $ dann +10 $ = 20 $."],
    "TMP3_12": ["Sie falten ein Blatt sieben Mal in der Mitte. Wie viele Schichten?", "Jede Falte verdoppelt die Lagen.", ["128", "64", "14", "256"], "2⁷ = 128."],
    "TMP3_13": ["Eine Primzahl multipliziert mit sich selbst ergibt 169. Was ist die Zahl?", "Die Quadratwurzel von 169.", ["13", "11", "17", "7"], "√169 = 13, was eine Primzahl ist."],
    "TMP3_14": ["Zwei Züge sind 100 Meilen voneinander entfernt und fahren jeweils 50 Meilen pro Stunde aufeinander zu. Eine Fliege fliegt mit 75 Meilen pro Stunde zwischen ihnen hindurch. Wie lange dauert es, bis sich die Züge treffen?", "Wie lange dauert es, bis sie sich treffen?", ["75 Meilen", "100 Meilen", "50 Meilen", "150 Meilen"], "Relative Geschwindigkeit 100 Meilen pro Stunde → 1 Stunde. Fliegen: 75 × 1 = 75 Meilen."],
    "TMP3_15": ["Was ist die kleinste Zahl, die durch 1, 2, 3, 4, 5 und 6 teilbar ist?", "Kleinstes gemeinsames Vielfaches (CMMMC).", ["60", "30", "120", "720"], "CMMMC(1…6) = 60."],
    "TMP3_16": ["Zählt man von 1 bis 100, wie oft kommt die Zahl 7 vor?", "Einheiten und Zehner getrennt.", ["20", "10", "11", "19"], "Einheiten: 7,17,…,97 – 10. Zehner: 70–79 – 10. Insgesamt 20."],
    "TMP3_17": ["Eine Zahl erhöht sich um 20 % und wird zu 60. Wie lautete sie ursprünglich?", "1,2x = 60.", ["50", "48", "72", "40"], "x = 60 / 1,2 = 50."],
    "TMP3_18": ["Sie falten ein Blatt zehnmal in der Mitte. Wie viele Schichten?", "Jede Falte verdoppelt sich.", ["1024", "100", "512", "2048"], "2¹⁰ = 1024."],
    "TMP3_19": ["Das Produkt zweier aufeinanderfolgender positiver Ganzzahlen ist 156. Was sind sie?", "Zwei aufeinanderfolgende Zahlen, deren Produkt 156 ist.", ["12 und 13", "11 und 12", "13 und 14", "10 und 15"], "12 × 13 = 156."],
    "TMP3_20": ["3×3 magisches Quadrat: Jede Zeile, Spalte und Diagonale ergibt zusammen 15. Erste Zeile [2, 7, 6], mittlere [9, 5, 1]. Was ist die erste Zahl in der letzten Zeile?", "Die erste Spalte ergibt ebenfalls 15.", ["4", "3", "6", "8"], "2 + 9 + ? = 15 → ? = 4."],
    "TMP4_1": ["Eine Bakterienkolonie verdoppelt sich stündlich und füllt mittags ein Glas vollständig aus. Um wie viel Uhr war das Glas bei einer Viertelstunde?", "Rückwärts gehen: Jede Stunde durch 2 dividieren.", ["10:00", "11:00", "9:00 Uhr", "6:00"], "Mittag: 100 %. 11:00: 50 %. 10:00: 25 %."],
    "TMP4_2": ["Sie haben 24 Münzen; einer ist falsch und einfacher. Wie viele Mindestwiegungen auf einer Waage gibt es, um es sicher zu finden?", "Teilen Sie sich bei jedem Schritt in drei Gruppen auf.", ["3", "4", "5", "2"], "8 gegen 8, dann in der leichten Gruppe 3 gegen 3, dann 1 gegen 1 – 3 Abwägungen."],
    "TMP4_3": ["Ein Seil wird in 3 Teile geschnitten. Jedes Stück wird in 3 kleinere geschnitten. Wie viele Stücke insgesamt?", "3 × 3.", ["9", "6", "12", "27"], "3 × 3 = 9."],
    "TMP4_4": ["Ein Wurm befindet sich am Boden eines 30 m langen Brunnens. Es steigt tagsüber 5 m und rutscht nachts 4 m. Wie viele Tage erscheint es?", "Am letzten Tag kommt es heraus, ohne zurückzurutschen.", ["26 Tage", "30 Tage", "25 Tage", "27 Tage"], "Netto +1 m/Tag. Nach 25 Tagen: 25 m. Tag 26: 25+5=30 m."],
    "TMP4_5": ["8 Männer bauen in 10 Tagen eine Mauer. Wie viele Tage mit 5 Männern?", "Gesamtarbeit = Personen × Tage.", ["16 Tage", "12 Tage", "20 Tage", "8 Tage"], "8×10 = 80 Manntage. 80/5 = 16 Tage."],
    "TMP4_6": ["Die Leitungen A und B füllen einen Tank in 6 bzw. 3 Stunden. Wie lange bleiben beide geöffnet?", "Addiert die Flüsse: 1/6 + 1/3 pro Stunde.", ["2 Stunden", "4,5 Stunden", "3 Stunden", "1,5 Stunden"], "1/6+2/6=1/2 pro Stunde → 2 Stunden."],
    "TMP4_7": ["Ein Rechteck ist dreimal so lang wie breit. Der Umfang beträgt 48 m. Was ist das Gebiet?", "l = 3w; 2(w+3w)=48.", ["108 m²", "96 m²", "144 m²", "48 m²"], "8w=48 → b=6, l=18, Fläche 108 m²."],
    "TMP4_8": ["Eine Zahl erhöht sich um 20 % und verringert sich dann um 20 %. Was ist die Nettoveränderung gegenüber dem Original?", "Wenden Sie die Prozentsätze einzeln an.", ["4 % Rückgang", "0%", "4 % Steigerung", "2 % Rabatt"], "100→120→96. -4 % netto."],
    "TMP4_9": ["Das Geschäft erhöht die Preise um 25 % und gewährt dann 20 % Rabatt. Die Nettoveränderung?", "1,25 × 0,80.", ["0 % (keine Änderung)", "+5 %", "-5%", "+45 %"], "1,25 × 0,80 = 1 – vorhanden."],
    "TMP4_10": ["Die Summe der ersten 20 positiven natürlichen Zahlen?", "n(n+1)/2.", ["210", "200", "190", "220"], "20×21/2 = 210."],
    "TMP4_11": ["Der Winkel zwischen den Zeigern der Uhr bei 4:30?", "Der Fahrplan liegt zwischen halb vier und fünf.", ["45°", "90°", "60°", "30°"], "Minute 180°, Stunde 135°, Differenz 45°."],
    "TMP4_12": ["Das Auto fährt 60 km mit 30 km/h, dann 60 km mit 60 km/h. Durchschnittsgeschwindigkeit?", "Gesamtstrecke / Gesamtzeit.", ["40 km/h", "45 km/h", "50 km/h", "35 km/h"], "2 h + 1 h = 3 h; 120/3 = 40 km/h."],
    "TMP4_13": ["Wenn 2¹⁰ = 1024, was ist 2¹²?", "2¹⁰ × 2².", ["4096", "2048", "8192", "1248"], "1024 × 4 = 4096."],
    "TMP4_14": ["Ein Wasserhahn füllt den Pool in 4 Stunden; Der Abfluss reinigt es in 8 Stunden. Wie lange dauert es, bis beide geöffnet sind?", "Nettodurchfluss = Füllen − Entleeren.", ["8 Stunden", "6 Stunden", "12 Stunden", "4 Stunden"], "1/4 − 1/8 = 1/8 pro Stunde → 8 Stunden."],
    "TMP4_15": ["Der Preis sinkt um 10 %, dann um weitere 10 %. Der totale Rückgang gegenüber dem Original?", "Die zweiten 10 % entfallen auf den bereits reduzierten Preis.", ["19 %", "20 %", "18 %", "21 %"], "0,9×0,9=0,81 → 19 % Abnahme."],
    "TMP4_16": ["Finden Sie x: 3x + 7 = 22.", "Isolieren Sie x.", ["5", "7", "3", "10"], "3x=15 → x=5."],
    "TMP4_17": ["Ein 100 m langer Zug fährt mit 50 m/s. Wie lange brauchen sie, um eine Stange vollständig zu passieren?", "Die Länge des Zuges muss abgedeckt werden.", ["2 Sekunden", "1 Sekunde", "4 Sekunden", "0,5 Sekunden"], "100/50 = 2 s."],
    "TMP4_18": ["Zwei Arbeiter erledigen eine Arbeit in 12 Tagen. Einer in 20 Tagen. Wie viel kostet der andere allein?", "1/12 − 1/20.", ["30 Tage", "24 Tage", "15 Tage", "40 Tage"], "1/30 pro Tag → 30 Tage."],
    "TMP4_19": ["Sie investieren 1000 $ zu 5 % einfachem Zins pro Jahr, 3 Jahre lang. Wie hoch sind die Gesamtzinsen?", "Einfacher Zins = Kapital × Zinssatz × Zeit.", ["150 $", "1150 $", "50 $", "300 $"], "1000 × 0,05 × 3 = 150 $."],
    "TMP4_20": ["Der Bauer hat Hühner und Kühe. 20 Köpfe und 56 Fuß. wie viele Hühner", "g + v = 20; 2g + 4v = 56.", ["12", "8", "14", "10"], "v=8, g=12."],
    "TMP5_1": ["Du hast zwei Seile; Jedes brennt in genau 1 Stunde vollständig ab, jedoch unregelmäßig. Wie misst man genau 45 Minuten?", "Was passiert, wenn man ein Seil an beiden Enden anzündet?", ["Sie zünden gleichzeitig Seil 1 an beiden Enden und Seil 2 an einem Ende an", "Sie zünden beide Seile an einem Ende an", "Schneiden Sie ein Seil in vier Teile und zünden Sie ein Stück an", "Man zündet ein Seil an, wartet, bis es brennt, und dann das andere"], "Seil 1 (beide Enden) brennt in 30 Minuten. Dann das andere Ende von Seil 2 anzünden – weitere 15 Minuten. Gesamt: 45 Min."],
    "TMP5_2": ["Zwei Väter und zwei Söhne essen. Essen Sie genau 3 Eier, jeweils eines. Wie ist das möglich?", "Kann eine Person zwei Rollen einnehmen?", ["Großvater, Vater und Sohn (3 Personen)", "Einer hat nicht gegessen", "Es waren 4, aber die Eier wurden geteilt", "Jemand hat zwei Eier gegessen"], "Drei Generationen: Großvater (Vater), Vater (und Sohn und Vater), Sohn. Zwei Väter + zwei Söhne = 3 Personen."],
    "TMP5_3": ["100 Schließfächer hintereinander, alle verschlossen. Student k wechselt jedes k-te Schließfach. Wie viele bleiben am Ende offen?", "Ein Schrank ist geöffnet, wenn er ungerade oft umgeschaltet wird. Welche Zahlen haben eine ungerade Anzahl an Teilern?", ["10", "50", "25", "0"], "Nur perfekte Quadrate: 1, 4, 9, 16, 25, 36, 49, 64, 81, 100 – 10 Schränke."],
    "TMP5_4": ["Drei Schalter außerhalb eines geschlossenen Raums steuern drei Glühbirnen im Inneren. Sie können nur einmal teilnehmen. Wie findet man heraus, wer wer ist?", "Eine Glühbirne, die längere Zeit eingeschaltet war, bleibt auch nach dem Ausschalten warm.", ["Schalter 1 EIN, warten, AUS; 2 EIN; Geben Sie ein: Warm aus=1, Ein=2, Kalt aus=3", "Wechseln Sie jeweils einen und prüfen Sie ihn jedes Mal", "Sie schalten alle drei schnell ein und aus und betreten dann den Raum", "Nach jedem Wechsel schaut man auf das Schlüsselloch"], "1 EIN für ein paar Minuten, AUS, 2 EIN, eingeben. Warm aus = 1. Ein = 2. Kalt aus = 3."],
    "TMP5_5": ["Drei Kisten mit der Aufschrift „Äpfel“, „Orangen“, „Mix“. Alle Etiketten sind falsch. Sie können eine Frucht aus einer Kiste nehmen. Von welchem?", "Das Feld „Mischung“ kann keine Mischung enthalten, wenn alle Etiketten falsch sind.", ["Feld „Mischen“.", "„Apfel“-Box", "Schachtel „Orangen“.", "Jede Kiste"], "Ziehen Sie aus der Kiste „Mix“: Der Inhalt ist einheitlich (kein Gemisch). Je nach Frucht lässt sich der Rest zuordnen — „Äpfel“ und „Orangen“ sind ja falsch beschriftet."],
    "TMP5_6": ["Ein Mann hat drei Töchter. Das Produkt des Alters ist 36. Die Summe ist die Nummer des Nachbarhauses (nicht eindeutig). Der Älteste spielt Klavier. Was sind die Altersgruppen?", "Zwei Tripel von Teilern von 36 haben die gleiche Summe. „Größte“ eliminiert einen Fall.", ["2, 2 und 9", "1, 6 und 6", "3, 3 und 4", "1, 4 und 9"], "Summen 13: {1,6,6} und {2,2,9}. Es gibt ein eindeutiges „Größtes“ → {2, 2, 9}."],
    "TMP5_7": ["Das Monty-Hall-Problem: Sie wählen Tür 1 von 3 (ein Auto, zwei Ziegen). Gastgeber öffnet Tür 3 – Ziege. Ziehst du dich an Tür 2 um?", "Wie hoch war die anfängliche Wahrscheinlichkeit für Ihre Tür?", ["Ja – in zwei Dritteln der Fälle gewinnt der Wandel", "Nein – es ist 50/50", "Es spielt keine Rolle", "Nein – die erste Wahl ist normalerweise richtig"], "Ihre Wahl: 1/3. Die verbleibende Tür ist 2/3. Durch den Wechsel verdoppeln sich die Chancen."],
    "TMP5_8": ["Wie viele Felder beliebiger Größe gibt es auf einem 8×8-Schachbrett?", "Count separately 1×1, 2×2, … 8×8.", ["204", "64", "256", "100"], "8²+7²+…+1² = 204."],
    "TMP5_9": ["Die Summe der Zahlen von 1 bis 100?", "Gaußsche Formel: n(n+1)/2.", ["5050", "5000", "10000", "10100"], "100×101/2 = 5050."],
    "TMP5_10": ["Wie viele Nullen am Ende von 100!?", "Die Nullstellen ergeben sich aus den Faktoren 10 = 2×5. Zählen Sie die Potenzen von 5.", ["24", "20", "25", "10"], "⌊100/5⌋ + ⌊100/25⌋ = 24."],
    "TMP5_11": ["Der Bauer überquert mit dem Wolf, der Ziege und dem Kohl den Fluss. Boot: Bauer + ein Gegenstand. Der Wolf frisst die allein gelassene Ziege; die Ziege frisst den Kohl. Womit fängt es an?", "Welches Paar kannst du alleine am Ufer lassen?", ["Ziege", "Der Wolf", "Kohl", "Es spielt keine Rolle"], "Zuerst die Ziege. Der Wolf und der Kohl sind in Sicherheit. Dann der Rest mit Wendungen."],
    "TMP5_12": ["Ausgehend von einem Kaninchenpaar reifen sie in einem Monat heran und bringen monatlich nach der Reife ein neues Paar hervor. Wie viele Paare nach 6 Monaten?", "Fibonacci-Folge: 1, 1, 2, 3, 5, 8, …", ["8", "13", "6", "10"], "Monat 1–6: 1, 1, 2, 3, 5, 8 Paare."],
    "TMP5_13": ["Mindestanzahl an Zügen in Towers of Hanoi mit 5 Scheiben?", "2ⁿ − 1, n = Anzahl der Scheiben.", ["31", "32", "63", "15"], "2⁵ − 1 = 31."],
    "TMP5_14": ["Mindestanzahl an Personen in einem Raum, sodass eine Wahrscheinlichkeit von >50 % besteht, dass zwei Personen denselben Geburtstag haben?", "Das Geburtstagsparadoxon – die Antwort ist weniger als man denkt.", ["23", "50", "183", "365"], "Bei 23 Personen liegt die Wahrscheinlichkeit bei über 50 %."],
    "TMP5_15": ["Wie hoch ist in einem Raum mit 23 Personen die ungefähre Wahrscheinlichkeit, dass mindestens zwei Personen denselben Geburtstag haben?", "Das Ergebnis des Geburtstagsparadoxons.", ["ca. 50 %", "ca. 6 %", "ca. 25 %", "etwa 75 %"], "Bei 23 Personen ~50,7 %."],
    "TMP5_16": ["Auf einer Insel sagen Ritter die Wahrheit, Gauner lügen. Zu sagen: „Wir sind beide Gauner.“ Was ist A?", "Wenn A ein Ritter wäre, könnte die Aussage wahr sein?", ["Betrüger", "Ritter", "Es kann nicht bestimmt werden", "Keine"], "Ein Ritter konnte nicht „beide Betrüger“ sagen. Also lügt A; Die Aussage ist falsch – sie sind nicht beide Gauner, der andere ist ein Ritter."],
    "TMP5_17": ["Die Summe der Innenwinkel eines Siebenecks (7 Seiten)?", "(n − 2) × 180°.", ["900°", "720°", "1080°", "1260°"], "5 × 180° = 900°."],
    "TMP5_18": ["Wie viele Quadrate beliebiger Größe in einem 4×4-Raster?", "1×1, 2×2, 3×3, 4×4.", ["30", "16", "20", "25"], "4²+3²+2²+1² = 30."],
    "TMP5_19": ["Sie werfen dreimal eine faire Münze. Wie groß ist die Wahrscheinlichkeit, mindestens einmal als „Kopf“ aufzutauchen?", "Die Ergänzung: niemals Kopf (dreimal Seite).", ["7/8", "3/4", "1/2", "1/8"], "P(kein Kopf) = (1/2)³ = 1/8. P(mindestens ein Kopf) = 7/8."],
    "TMP5_20": ["Wie viele Rechtecke gibt es in den Linien eines 3×3-Rasters (4 horizontal, 4 vertikal)?", "Sie wählen 2 horizontale und 2 vertikale.", ["36", "18", "24", "9"], "C(4,2)² = 36."],
  }
});
